@import "tailwindcss";

@theme inline {
  --font-sans: var(--font-geist);
  --font-serif: var(--font-lora);
}

@theme {
  /* Base — Spotify-dark neutral scale */
  --color-well-50:  #ffffff;   /* primary text — pure white */
  --color-well-100: #f5f5f5;
  --color-well-200: #e0e0e0;
  --color-well-300: #b3b3b3;   /* Spotify secondary text */
  --color-well-400: #9e9e9e;
  --color-well-500: #6a6a6a;
  --color-well-600: #535353;   /* Spotify muted */
  --color-well-700: #404040;
  --color-well-800: #282828;   /* elevated card */
  --color-well-900: #181818;   /* card background */
  --color-well-950: #121212;   /* page background */

  /* Cream — warm white primary interactive */
  --color-cream-50:  #fffefb;
  --color-cream-100: #fdfaf4;
  --color-cream-200: #f5f0e8;   /* primary buttons, links, active states */
  --color-cream-300: #ede5d6;
  --color-cream-400: #d6c9b4;
  --color-cream-500: #b8a890;
  --color-cream-600: #8f7a60;
  --color-cream-700: #6b5840;
  --color-cream-800: #3d2e1e;
  --color-cream-900: #211608;
  --color-cream-950: #120c03;

  /* Gold — secondary accent */
  --color-gold-50:  #fdf9ee;
  --color-gold-100: #faf0d0;
  --color-gold-200: #f2dc9a;
  --color-gold-300: #e8c660;
  --color-gold-400: #d4a853;   /* secondary accent, badges */
  --color-gold-500: #c9963e;
  --color-gold-600: #b07a28;
  --color-gold-700: #8a5e1a;
  --color-gold-800: #5c3c10;
  --color-gold-900: #321f08;
  --color-gold-950: #1a0e02;
}

*, *::before, *::after {
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-sans), system-ui, sans-serif;
  background-color: #121212;
}

/* Thin, unobtrusive scrollbar */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background-color: #404040;
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background-color: #535353;
}

import type { Metadata } from 'next'
import { Geist, Lora } from 'next/font/google'
import './globals.css'

const geist = Geist({ subsets: ['latin'], variable: '--font-geist' })
const lora = Lora({ subsets: ['latin'], variable: '--font-lora' })

export const metadata: Metadata = {
  title: 'MindWell',
  description: 'A deep, still space for reading and reflection',
  manifest: '/manifest.json',
  appleWebApp: {
    capable: true,
    statusBarStyle: 'black-translucent',
    title: 'MindWell',
  },
  icons: {
    icon: [
      { url: '/favicon-16x16.png', sizes: '16x16', type: 'image/png' },
      { url: '/favicon-32x32.png', sizes: '32x32', type: 'image/png' },
    ],
    shortcut: '/favicon.ico',
    apple: '/apple-touch-icon.png',
  },
}

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <body className={`${geist.variable} ${lora.variable} antialiased bg-well-950 text-well-50`}>
        {children}
      </body>
    </html>
  )
}

import { createClient } from '@supabase/supabase-js'
import type { Book, BookNote, Quote, Connection, NoteTab, SearchResult } from '@/types'

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!

export const supabase = createClient(supabaseUrl, supabaseAnonKey)

// Typed helpers

export async function getBooks() {
  const { data, error } = await supabase
    .from('books')
    .select('*')
    .order('created_at', { ascending: false })
  if (error) throw error
  return data as Book[]
}

export async function getBook(id: string) {
  const { data, error } = await supabase
    .from('books')
    .select('*')
    .eq('id', id)
    .single()
  if (error) throw error
  return data as Book
}

export async function createBook(book: Omit<Book, 'id' | 'created_at' | 'updated_at'>) {
  const { data, error } = await supabase
    .from('books')
    .insert(book)
    .select()
    .single()
  if (error) throw error
  return data as Book
}

export async function updateBook(id: string, updates: Partial<Book>) {
  const { data, error } = await supabase
    .from('books')
    .update(updates)
    .eq('id', id)
    .select()
    .single()
  if (error) throw error
  return data as Book
}

export async function deleteBook(id: string) {
  const { error } = await supabase.from('books').delete().eq('id', id)
  if (error) throw error
}

// Notes

export async function getNotesForBook(bookId: string) {
  const { data, error } = await supabase
    .from('book_notes')
    .select('*')
    .eq('book_id', bookId)
  if (error) throw error
  return data as BookNote[]
}

export async function upsertNote(bookId: string, tab: NoteTab, content: string) {
  const { data, error } = await supabase
    .from('book_notes')
    .upsert({ book_id: bookId, tab, content }, { onConflict: 'book_id,tab' })
    .select()
    .single()
  if (error) throw error
  return data as BookNote
}

// Quotes

export async function getQuotesForBook(bookId: string) {
  const { data, error } = await supabase
    .from('quotes')
    .select('*')
    .eq('book_id', bookId)
    .order('page_number', { ascending: true, nullsFirst: false })
    .order('created_at', { ascending: true })
  if (error) throw error
  return (data as Quote[]).map(q => ({ ...q, tags: q.tags ?? [] }))
}

export async function createQuote(quote: Omit<Quote, 'id' | 'created_at'>) {
  const { data, error } = await supabase
    .from('quotes')
    .insert({ ...quote, tags: quote.tags ?? [] })
    .select()
    .single()
  if (error) throw error
  return { ...(data as Quote), tags: (data as Quote).tags ?? [] }
}

export async function updateQuote(id: string, updates: Partial<Quote>) {
  const { data, error } = await supabase
    .from('quotes')
    .update(updates)
    .eq('id', id)
    .select()
    .single()
  if (error) throw error
  return { ...(data as Quote), tags: (data as Quote).tags ?? [] }
}

export async function deleteQuote(id: string) {
  const { error } = await supabase.from('quotes').delete().eq('id', id)
  if (error) throw error
}

// Connections

export async function getConnectionsForSource(sourceId: string) {
  const { data, error } = await supabase
    .from('connections')
    .select('*')
    .eq('source_id', sourceId)
    .order('created_at', { ascending: true })
  if (error) throw error
  return data as Connection[]
}

export async function createConnection(conn: Omit<Connection, 'id' | 'created_at'>) {
  const { data, error } = await supabase
    .from('connections')
    .insert(conn)
    .select()
    .single()
  if (error) throw error
  return data as Connection
}

export async function deleteConnection(id: string) {
  const { error } = await supabase.from('connections').delete().eq('id', id)
  if (error) throw error
}

// Global search

export async function searchAll(query: string): Promise<SearchResult[]> {
  if (!query.trim() || query.trim().length < 2) return []

  const q = query.trim()

  const [quotesRes, notesRes] = await Promise.all([
    supabase
      .from('quotes')
      .select('*, book:books(id, title)')
      .ilike('quote_text', `%${q}%`)
      .limit(30),
    supabase
      .from('book_notes')
      .select('*, book:books(id, title)')
      .ilike('content', `%${q}%`)
      .limit(30),
  ])

  const results: SearchResult[] = []

  for (const quote of quotesRes.data ?? []) {
    const book = quote.book as Book
    results.push({
      type: 'quote',
      id: quote.id,
      bookId: book.id,
      bookTitle: book.title,
      content: quote.quote_text,
      tags: quote.tags ?? [],
      pageNumber: quote.page_number,
    })
  }

  // Also search by tag (exact tag match)
  const tagQuotesRes = await supabase
    .from('quotes')
    .select('*, book:books(id, title)')
    .contains('tags', [q])
    .limit(20)

  for (const quote of tagQuotesRes.data ?? []) {
    if (results.find(r => r.id === quote.id)) continue
    const book = quote.book as Book
    results.push({
      type: 'quote',
      id: quote.id,
      bookId: book.id,
      bookTitle: book.title,
      content: quote.quote_text,
      tags: quote.tags ?? [],
      pageNumber: quote.page_number,
    })
  }

  for (const note of notesRes.data ?? []) {
    const book = note.book as Book
    results.push({
      type: 'note',
      id: note.id,
      bookId: book.id,
      bookTitle: book.title,
      content: note.content,
      tab: note.tab,
    })
  }

  return results
}

// Tag search — returns all quotes with the given tag across all books
export async function searchByTag(tag: string): Promise<(Quote & { book: Book })[]> {
  const { data, error } = await supabase
    .from('quotes')
    .select('*, book:books(*)')
    .contains('tags', [tag])
    .order('created_at', { ascending: true })
  if (error) throw error
  return (data ?? []).map(q => ({ ...q, tags: q.tags ?? [], book: q.book as Book }))
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import {
  DndContext,
  closestCenter,
  DragEndEvent,
  DragOverlay,
  DragStartEvent,
  PointerSensor,
  useDroppable,
  useSensor,
  useSensors,
} from '@dnd-kit/core'
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
  arrayMove,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import AddBookModal from '@/components/AddBookModal'
import AddArticleModal from '@/components/AddArticleModal'
import EditBookModal from '@/components/EditBookModal'
import GlobalSearch from '@/components/GlobalSearch'
import type { Book } from '@/types'

const READING_SECTION = '__reading-now__'
const QUEUE_SECTION = '__next-up__'

// ── Drag handle SVG ────────────────────────────────────────────────────────────

function DragHandle() {
  return (
    <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
      <circle cx="4" cy="3" r="1.5" />
      <circle cx="8" cy="3" r="1.5" />
      <circle cx="4" cy="8" r="1.5" />
      <circle cx="8" cy="8" r="1.5" />
      <circle cx="4" cy="13" r="1.5" />
      <circle cx="8" cy="13" r="1.5" />
    </svg>
  )
}

// ── Book card content (shared between sortable row + drag overlay) ─────────────

function BookCardContent({ book }: { book: Book }) {
  const pct = book.total_pages > 0
    ? Math.round((book.current_page / book.total_pages) * 100)
    : 0
  const isQueued = book.status === 'queued'

  return (
    <div className="flex-1 min-w-0">
      <p className="font-medium text-cream-200 truncate">{book.title}</p>
      {!isQueued && (
        <div className="flex items-center gap-2.5 mt-1.5">
          <div className="w-32 bg-well-800 rounded-full h-1">
            <div
              className="bg-gold-400 h-1 rounded-full transition-all"
              style={{ width: `${pct}%` }}
            />
          </div>
          <p className="text-xs text-well-400">
            p.&nbsp;{book.current_page}/{book.total_pages}
          </p>
        </div>
      )}
    </div>
  )
}

// ── Drag overlay card ─────────────────────────────────────────────────────────

function BookDragOverlay({ book }: { book: Book }) {
  return (
    <div className="bg-well-800 rounded-xl px-4 py-3 flex items-center gap-3 shadow-[0_16px_48px_rgba(0,0,0,0.8)] cursor-grabbing opacity-95">
      <div className="text-well-500 shrink-0">
        <DragHandle />
      </div>
      <BookCardContent book={book} />
    </div>
  )
}

// ── Sortable book row ──────────────────────────────────────────────────────────

function SortableBookRow({
  book,
  onComplete,
  onEdit,
  onMoveUp,
}: {
  book: Book
  onComplete: (book: Book) => void
  onEdit: (book: Book) => void
  onMoveUp?: () => void
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: book.id,
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.35 : 1,
  }

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="bg-well-900 rounded-xl px-4 py-3 flex items-center gap-3 transition-colors hover:bg-well-800 group"
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="text-well-700 hover:text-well-500 cursor-grab active:cursor-grabbing shrink-0 touch-none transition-colors"
        aria-label="Drag to reorder or move between sections"
      >
        <DragHandle />
      </button>

      <BookCardContent book={book} />

      <div className="flex items-center gap-2 shrink-0">
        <button
          onClick={() => onEdit(book)}
          className="text-xs text-well-500 hover:text-cream-200 px-2.5 py-1 rounded-md bg-well-800 hover:bg-well-700 transition-all"
        >
          Edit
        </button>
        <Link
          href={`/books/${book.id}`}
          className="text-xs text-well-500 hover:text-cream-200 px-2.5 py-1 rounded-md bg-well-800 hover:bg-well-700 transition-all"
        >
          Notes
        </Link>
        {onMoveUp ? (
          <button
            onClick={onMoveUp}
            className="text-xs text-well-500 hover:text-cream-200 px-2.5 py-1 rounded-md bg-well-800 hover:bg-well-700 transition-all"
          >
            Move Up
          </button>
        ) : (
          <button
            onClick={() => onComplete(book)}
            className="w-6 h-6 flex items-center justify-center rounded-full text-well-600 hover:text-well-950 hover:bg-cream-200 transition-all"
            title="Mark as finished"
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
              <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
            </svg>
          </button>
        )}
      </div>
    </div>
  )
}

// ── Droppable section container ────────────────────────────────────────────────

function DroppableSection({
  id,
  children,
  className = '',
}: {
  id: string
  children: React.ReactNode
  className?: string
}) {
  const { setNodeRef, isOver } = useDroppable({ id })
  return (
    <div
      ref={setNodeRef}
      className={`${className} rounded-xl transition-all ${isOver ? 'ring-1 ring-inset ring-cream-200/15' : ''}`}
    >
      {children}
    </div>
  )
}

// ── Article card ───────────────────────────────────────────────────────────────

function ArticleCard({ book, onDone, onEdit }: { book: Book; onDone: () => void; onEdit: (book: Book) => void }) {
  const [loading, setLoading] = useState(false)

  async function handleDone() {
    setLoading(true)
    await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'completed' }),
    })
    onDone()
  }

  return (
    <div className="bg-well-900 rounded-xl px-4 py-3 flex items-center gap-3 hover:bg-well-800 transition-colors">
      <div className="flex-1 min-w-0">
