// ── Tag input ──────────────────────────────────────────────────────────────

function TagInput({
  tags,
  onChange,
}: {
  tags: string[]
  onChange: (tags: string[]) => void
}) {
  const [input, setInput] = useState('')
  const inputRef = useRef<HTMLInputElement>(null)

  function addTag(raw: string) {
    const tag = raw.trim().toLowerCase().replace(/\s+/g, '-')
    if (!tag || tags.includes(tag)) {
      setInput('')
      return
    }
    onChange([...tags, tag])
    setInput('')
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault()
      addTag(input)
    }
    if (e.key === 'Backspace' && !input && tags.length > 0) {
      onChange(tags.slice(0, -1))
    }
  }

  return (
    <div
      className="flex flex-wrap gap-1.5 items-center min-h-8 px-2 py-1.5 bg-well-800 border-0 rounded-lg cursor-text"
      onClick={() => inputRef.current?.focus()}
    >
      {tags.map(tag => (
        <span
          key={tag}
          className={`inline-flex items-center gap-1 text-xs px-2 py-0.5 rounded-full border ${tagColor(tag)}`}
        >
          {tag}
          <button
            onClick={e => { e.stopPropagation(); onChange(tags.filter(t => t !== tag)) }}
            className="hover:text-white ml-0.5 leading-none"
          >
            ×
          </button>
        </span>
      ))}
      <input
        ref={inputRef}
        value={input}
        onChange={e => setInput(e.target.value)}
        onKeyDown={handleKeyDown}
        onBlur={() => { if (input.trim()) addTag(input) }}
        placeholder={tags.length === 0 ? 'Add tags…' : ''}
        className="flex-1 min-w-[80px] bg-transparent text-xs text-well-100 placeholder:text-well-400 outline-none"
      />
    </div>
  )
}

// ── Quote widget ────────────────────────────────────────────────────────────

function QuoteWidget({
  quote,
  onUpdate,
  onDelete,
}: {
  quote: Quote
  onUpdate: (updated: Quote) => void
  onDelete: (id: string) => void
}) {
  const [expanded, setExpanded] = useState(false)
  const [editing, setEditing] = useState(false)
  const [editText, setEditText] = useState(quote.quote_text)
  const [editPage, setEditPage] = useState(quote.page_number?.toString() ?? '')
  const [editTags, setEditTags] = useState<string[]>(quote.tags ?? [])
  const [saving, setSaving] = useState(false)
  const [tags, setTags] = useState<string[]>(quote.tags ?? [])

  // Keep local tags in sync with prop
  useEffect(() => { setTags(quote.tags ?? []) }, [quote.tags])

  async function handleSaveEdit() {
    setSaving(true)
    const updates = {
      quote_text: editText.trim(),
      page_number: editPage ? Number(editPage) : null,
      tags: editTags,
    }
    const { data, error } = await supabase
      .from('quotes')
      .update(updates)
      .eq('id', quote.id)
      .select()
      .single()
    if (!error && data) {
      onUpdate({ ...data as Quote, tags: (data as Quote).tags ?? [] })
    }
    setSaving(false)
    setEditing(false)
  }

  async function handleTagsChange(newTags: string[]) {
    setTags(newTags)
    const { data, error } = await supabase
      .from('quotes')
      .update({ tags: newTags })
      .eq('id', quote.id)
      .select()
      .single()
    if (!error && data) {
      onUpdate({ ...data as Quote, tags: newTags })
    }
  }

  const preview = quote.quote_text.length > 140
    ? quote.quote_text.slice(0, 140).trim() + '…'
    : quote.quote_text

  if (editing) {
    return (
      <div className="bg-well-800 rounded-xl ring-2 ring-cream-200/20 shadow-[0_4px_20px_rgba(0,0,0,0.5)] p-4 space-y-3">
        <textarea
          autoFocus
          value={editText}
          onChange={e => setEditText(e.target.value)}
          rows={4}
          className="w-full resize-none bg-well-800 border-0 rounded-lg px-3 py-2.5 text-sm text-well-50 leading-relaxed placeholder:text-well-400 focus:outline-none focus:ring-2 focus:ring-cream-200/20 transition-all"
        />
        <div className="flex gap-2 items-center">
          <label className="text-sm text-well-300 shrink-0">p.</label>
          <input
            type="number"
            min={1}
            value={editPage}
            onChange={e => setEditPage(e.target.value)}
            placeholder="—"
            className="w-16 bg-well-800 border-0 rounded-lg px-2 py-2 text-sm text-well-100 focus:outline-none focus:ring-2 focus:ring-cream-200/20 transition-all"
          />
        </div>
        <TagInput tags={editTags} onChange={setEditTags} />
        <div className="flex gap-2 justify-end">
          <button
            onClick={() => { setEditing(false); setEditText(quote.quote_text); setEditPage(quote.page_number?.toString() ?? ''); setEditTags(quote.tags ?? []) }}
            className="text-sm text-well-300 hover:text-well-100 px-3 py-1.5 rounded-lg transition-colors"
          >
            Cancel
          </button>
          <button
            onClick={handleSaveEdit}
            disabled={saving || !editText.trim()}
            className="bg-cream-200 hover:bg-cream-100 text-well-950 px-4 py-2 rounded-full text-sm font-medium transition-all disabled:opacity-40 "
          >
            {saving ? 'Saving…' : 'Save'}
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className={`rounded-xl transition-all ${
      expanded
        ? 'bg-well-800 shadow-[0_4px_24px_rgba(0,0,0,0.5)]'
        : 'bg-well-900 hover:bg-well-800'
    }`}>

      {/* Collapsed header — always visible */}
      <div
        className="px-4 pt-4 pb-3 cursor-pointer"
        onClick={() => setExpanded(e => !e)}
      >
        {/* Page number + actions row */}
        <div className="flex items-start justify-between gap-3 mb-2">
          <div className="flex items-center gap-2">
            {quote.page_number != null && (
              <span className="text-xs font-mono text-well-400 bg-well-800/60 border border-well-700/40 px-1.5 py-0.5 rounded">
                p.{quote.page_number}
              </span>
            )}
          </div>
          <div className="flex items-center gap-1.5 shrink-0">
            <button
              onClick={e => { e.stopPropagation(); setEditing(true); setExpanded(true) }}
              className="text-well-500 hover:text-well-200 p-1 rounded transition-colors"
              title="Edit"
            >
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
                <path d="M2.695 14.763l-1.262 3.154a.5.5 0 0 0 .65.65l3.155-1.262a4 4 0 0 0 1.343-.885L17.5 5.5a2.121 2.121 0 0 0-3-3L3.58 13.42a4 4 0 0 0-.885 1.343Z" />
              </svg>
            </button>
            <button
              onClick={e => { e.stopPropagation(); onDelete(quote.id) }}
              className="text-well-500 hover:text-rose-400 p-1 rounded transition-colors"
              title="Delete"
            >
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
                <path fillRule="evenodd" d="M8.75 1A2.75 2.75 0 0 0 6 3.75v.443c-.795.077-1.584.176-2.365.298a.75.75 0 1 0 .23 1.482l.149-.022.841 10.518A2.75 2.75 0 0 0 7.596 19h4.807a2.75 2.75 0 0 0 2.742-2.53l.841-10.52.149.023a.75.75 0 0 0 .23-1.482A41.03 41.03 0 0 0 14 4.193V3.75A2.75 2.75 0 0 0 11.25 1h-2.5ZM10 4c.84 0 1.673.025 2.5.075V3.75c0-.69-.56-1.25-1.25-1.25h-2.5c-.69 0-1.25.56-1.25 1.25v.325C8.327 4.025 9.16 4 10 4ZM8.58 7.72a.75.75 0 0 0-1.5.06l.3 7.5a.75.75 0 1 0 1.5-.06l-.3-7.5Zm4.34.06a.75.75 0 1 0-1.5-.06l-.3 7.5a.75.75 0 1 0 1.5.06l.3-7.5Z" clipRule="evenodd" />
              </svg>
            </button>
            <button
              className="text-well-500 hover:text-well-200 p-1 rounded transition-colors"
              title={expanded ? 'Collapse' : 'Expand'}
            >
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className={`w-3.5 h-3.5 transition-transform ${expanded ? 'rotate-180' : ''}`}>
                <path fillRule="evenodd" d="M5.22 8.22a.75.75 0 0 1 1.06 0L10 11.94l3.72-3.72a.75.75 0 1 1 1.06 1.06l-4.25 4.25a.75.75 0 0 1-1.06 0L5.22 9.28a.75.75 0 0 1 0-1.06Z" clipRule="evenodd" />
              </svg>
            </button>
          </div>
        </div>

        {/* Quote preview */}
        <p className="text-sm text-well-100 leading-relaxed italic">
          &ldquo;{expanded ? quote.quote_text : preview}&rdquo;
        </p>

        {/* Tags */}
        {tags.length > 0 && (
          <div className="flex flex-wrap gap-1.5 mt-2.5">
            {tags.map(tag => (
              <span
                key={tag}
                className={`inline-flex items-center text-xs px-2 py-0.5 rounded-full border ${tagColor(tag)}`}
              >
                {tag}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Expanded section */}
      {expanded && (
        <div className="px-4 pb-4 border-t border-well-800/60 pt-3 space-y-3">
          {/* Copy button */}
          <div className="flex justify-end">
            <CopyButton text={quote.quote_text} />
          </div>

          {/* Tag editor */}
          <div>
            <p className="text-[11px] font-medium uppercase tracking-wider text-well-400 mb-1.5">Tags</p>
            <TagInput tags={tags} onChange={handleTagsChange} />
          </div>
        </div>
      )}
    </div>
  )
}

