interface Props {
  bookId: string
  quotes: Quote[]
  onUpdate: (quotes: Quote[]) => void
}

export default function Quotes({ bookId, quotes, onUpdate }: Props) {
  const [addOpen, setAddOpen] = useState(false)
  const [addText, setAddText] = useState('')
  const [addPage, setAddPage] = useState('')
  const [addTags, setAddTags] = useState<string[]>([])
  const [adding, setAdding] = useState(false)

  // Sort by page number (nulls last), then creation time
  const sorted = [...quotes].sort((a, b) => {
    if (a.page_number == null && b.page_number == null) return 0
    if (a.page_number == null) return 1
    if (b.page_number == null) return -1
    return a.page_number - b.page_number
  })

  async function handleAdd() {
    if (!addText.trim()) return
    setAdding(true)
    const { data, error } = await supabase
      .from('quotes')
      .insert({
        book_id: bookId,
        quote_text: addText.trim(),
        page_number: addPage ? Number(addPage) : null,
        tags: addTags,
        heading_id: null,
        sort_order: null,
      })
      .select()
      .single()
    if (!error && data) {
      const newQuote = { ...data as Quote, tags: (data as Quote).tags ?? [] }
      onUpdate([...quotes, newQuote])
      setAddText('')
      setAddPage('')
      setAddTags([])
      setAddOpen(false)
    }
    setAdding(false)
  }

  function handleUpdate(updated: Quote) {
    onUpdate(quotes.map(q => q.id === updated.id ? updated : q))
  }

  async function handleDelete(id: string) {
    await supabase.from('quotes').delete().eq('id', id)
    onUpdate(quotes.filter(q => q.id !== id))
  }

  return (
    <div className="space-y-3">
      {/* Add quote form */}
      {addOpen ? (
        <div className="bg-well-800 rounded-xl ring-2 ring-cream-200/20 shadow-[0_4px_20px_rgba(0,0,0,0.5)] p-4 space-y-3">
          <textarea
            autoFocus
            value={addText}
            onChange={e => setAddText(e.target.value)}
            placeholder="Paste or type quote text…"
            rows={3}
            className="w-full resize-none bg-well-800 border-0 rounded-lg px-3 py-2.5 text-sm text-well-50 leading-relaxed placeholder:text-well-400 focus:outline-none focus:ring-2 focus:ring-cream-200/20 transition-all"
          />
          <div className="flex gap-2 items-center">
            <label className="text-sm text-well-300 shrink-0">p.</label>
            <input
              type="number"
              min={1}
              value={addPage}
              onChange={e => setAddPage(e.target.value)}
              placeholder="—"
              className="w-16 bg-well-800 border-0 rounded-lg px-2 py-2 text-sm text-well-100 focus:outline-none focus:ring-2 focus:ring-cream-200/20 transition-all"
            />
          </div>
          <TagInput tags={addTags} onChange={setAddTags} />
          <div className="flex gap-2 justify-end">
            <button
              onClick={() => { setAddOpen(false); setAddText(''); setAddPage(''); setAddTags([]) }}
              className="text-sm text-well-300 hover:text-well-100 px-3 py-1.5 rounded-lg transition-colors"
            >
              Cancel
            </button>
            <button
              onClick={handleAdd}
              disabled={adding || !addText.trim()}
              className="bg-cream-200 hover:bg-cream-100 text-well-950 px-4 py-2 rounded-full text-sm font-medium transition-all disabled:opacity-40 "
            >
              {adding ? 'Adding…' : 'Add quote'}
            </button>
          </div>
        </div>
      ) : (
        <button
          onClick={() => setAddOpen(true)}
          className="w-full text-left text-sm text-well-400 hover:text-well-100 border border-dashed border-well-700 hover:border-well-600 rounded-xl px-4 py-3 transition-all hover:bg-well-900/50"
        >
          + Add quote
        </button>
      )}

      {/* Quote list */}
      {sorted.length === 0 && !addOpen && (
        <div className="text-center py-12 text-well-400">
          <p className="text-3xl mb-3 opacity-50">❝</p>
          <p className="text-sm">No quotes yet. Add your first passage.</p>
        </div>
      )}

      {sorted.map(quote => (
        <QuoteWidget
          key={quote.id}
          quote={quote}
          onUpdate={handleUpdate}
          onDelete={handleDelete}
        />
      ))}
    </div>
  )
}

'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import type { Book, Quote, SearchResult } from '@/types'

const TAG_PALETTES = [
  'bg-blue-900/60 text-blue-300 border-blue-700/50',
  'bg-violet-900/60 text-violet-300 border-violet-700/50',
  'bg-emerald-900/60 text-emerald-300 border-emerald-700/50',
  'bg-amber-900/60 text-amber-300 border-amber-700/50',
  'bg-rose-900/60 text-rose-300 border-rose-700/50',
  'bg-teal-900/60 text-teal-300 border-teal-700/50',
  'bg-indigo-900/60 text-indigo-300 border-indigo-700/50',
  'bg-orange-900/60 text-orange-300 border-orange-700/50',
]

function tagColor(tag: string): string {
  let hash = 0
  for (let i = 0; i < tag.length; i++) {
    hash = (hash * 31 + tag.charCodeAt(i)) & 0xffffffff
  }
  return TAG_PALETTES[Math.abs(hash) % TAG_PALETTES.length]
}

function highlight(text: string, query: string): React.ReactNode {
  if (!query.trim()) return text
  const idx = text.toLowerCase().indexOf(query.toLowerCase())
  if (idx === -1) return text
  return (
    <>
      {text.slice(0, idx)}
      <mark className="bg-gold-400/25 text-gold-300 rounded-sm">{text.slice(idx, idx + query.length)}</mark>
      {text.slice(idx + query.length)}
    </>
  )
}

function excerpt(text: string, query: string, maxLen = 160): string {
  const idx = text.toLowerCase().indexOf(query.toLowerCase())
  if (idx === -1) return text.slice(0, maxLen) + (text.length > maxLen ? '…' : '')
  const start = Math.max(0, idx - 40)
  const end = Math.min(text.length, idx + query.length + 100)
  return (start > 0 ? '…' : '') + text.slice(start, end) + (end < text.length ? '…' : '')
}

// Group results by book
function groupByBook(results: SearchResult[]): Map<string, { title: string; items: SearchResult[] }> {
  const map = new Map<string, { title: string; items: SearchResult[] }>()
  for (const r of results) {
    if (!map.has(r.bookId)) {
      map.set(r.bookId, { title: r.bookTitle, items: [] })
    }
    map.get(r.bookId)!.items.push(r)
  }
  return map
}

function groupTagResultsByBook(quotes: (Quote & { book: Book })[]): Map<string, { title: string; quotes: (Quote & { book: Book })[] }> {
  const map = new Map<string, { title: string; quotes: (Quote & { book: Book })[] }>()
  for (const q of quotes) {
    if (!map.has(q.book_id)) {
      map.set(q.book_id, { title: q.book.title, quotes: [] })
    }
    map.get(q.book_id)!.quotes.push(q)
  }
  return map
}

function typeLabel(r: SearchResult): string {
  if (r.type === 'quote') return 'Quote'
  const tab = r.tab ?? 'note'
  return tab.charAt(0).toUpperCase() + tab.slice(1)
}

function typeBadge(r: SearchResult): string {
  if (r.type === 'quote') return 'bg-gold-900/50 text-gold-300 border-gold-700/50'
  return 'bg-well-800/80 text-well-300 border-well-700/50'
}

interface Props {
  onClose: () => void
}

export default function GlobalSearch({ onClose }: Props) {
  const router = useRouter()
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<SearchResult[]>([])
  const [tagResults, setTagResults] = useState<(Quote & { book: Book })[]>([])
  const [loading, setLoading] = useState(false)
  const [exportingPDF, setExportingPDF] = useState(false)
  const inputRef = useRef<HTMLInputElement>(null)
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  const isTagMode = query.trim().startsWith('#')
  const tagQuery = isTagMode ? query.trim().slice(1).trim() : ''

  useEffect(() => {
    inputRef.current?.focus()
  }, [])

  // Close on Escape
  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') onClose()
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [onClose])

  const searchText = useCallback(async (q: string) => {
    if (!q.trim() || q.trim().length < 2) {
      setResults([])
      setLoading(false)
      return
    }
    setLoading(true)
    const res = await fetch(`/api/search?q=${encodeURIComponent(q.trim())}`)
    const json = await res.json()
    setResults(json.results ?? [])
    setLoading(false)
  }, [])

  const searchTag = useCallback(async (tag: string) => {
    if (!tag.trim() || tag.trim().length < 1) {
      setTagResults([])
      setLoading(false)
      return
    }
    setLoading(true)
    const res = await fetch(`/api/tag-search?tag=${encodeURIComponent(tag.trim())}`)
    const json = await res.json()
    setTagResults(json.quotes ?? [])
    setLoading(false)
  }, [])

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    const val = e.target.value
    setQuery(val)
    setResults([])
    setTagResults([])
    if (debounceRef.current) clearTimeout(debounceRef.current)

    const trimmed = val.trim()
    if (trimmed.startsWith('#')) {
      const tag = trimmed.slice(1).trim()
      debounceRef.current = setTimeout(() => searchTag(tag), 300)
    } else {
      debounceRef.current = setTimeout(() => searchText(val), 300)
    }
  }

  function navigateTo(result: SearchResult) {
    router.push(`/books/${result.bookId}?tab=${result.type === 'quote' ? 'quotes' : (result.tab ?? 'outline')}`)
    onClose()
  }

  async function handleExportTagPDF() {
    if (!tagQuery) return
    setExportingPDF(true)
    const res = await fetch(`/api/export/tag-search?tag=${encodeURIComponent(tagQuery)}`)
    if (res.ok) {
      const blob = await res.blob()
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `${tagQuery}-quotes.pdf`
      a.click()
      URL.revokeObjectURL(url)
    }
    setExportingPDF(false)
  }

  const groups = groupByBook(results)
  const tagGroups = groupTagResultsByBook(tagResults)

  const minLen = isTagMode ? 1 : 2
  const hasQuery = isTagMode ? tagQuery.length >= minLen : query.trim().length >= minLen
  const hasResults = isTagMode ? tagResults.length > 0 : results.length > 0

  return (
    <div
      className="fixed inset-0 bg-well-950/90 backdrop-blur-sm flex items-start justify-center z-50 pt-[15vh] px-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="w-full max-w-2xl bg-well-900 rounded-2xl shadow-[0_24px_80px_rgba(0,0,0,0.95),0_0_0_1px_rgba(255,255,255,0.06)] overflow-hidden">

        {/* Search input */}
        <div className="flex items-center gap-3 px-5 py-4 border-b border-well-800">
          {isTagMode ? (
            <span className="text-gold-400 font-semibold text-base shrink-0">#</span>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-5 h-5 text-well-400 shrink-0">
              <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
            </svg>
          )}
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={handleChange}
            placeholder="Search notes, quotes… or #tag for tag search"
            className="flex-1 bg-transparent text-well-50 placeholder:text-well-400 text-base outline-none"
          />
          {loading && (
            <div className="w-4 h-4 border-2 border-well-700 border-t-cream-400 rounded-full animate-spin shrink-0" />
          )}
          {isTagMode && tagResults.length > 0 && (
            <button
              onClick={handleExportTagPDF}
              disabled={exportingPDF}
              className="shrink-0 text-xs text-well-950 bg-cream-200 hover:bg-cream-100 px-3 py-1.5 rounded-full font-medium transition-all disabled:opacity-50"
            >
              {exportingPDF ? 'Exporting…' : '↓ PDF'}
            </button>
          )}
          <button
            onClick={onClose}
            className="text-well-400 hover:text-well-100 text-xl leading-none shrink-0 transition-colors"
          >
            ×
          </button>
        </div>

        {/* Results */}
        <div className="max-h-[60vh] overflow-y-auto">
          {hasQuery && !loading && !hasResults && (
            <div className="px-5 py-10 text-center text-well-400 text-sm">
              No results for &ldquo;{isTagMode ? `#${tagQuery}` : query}&rdquo;
            </div>
          )}

          {!hasQuery && (
            <div className="px-5 py-8 text-center text-well-400 text-sm">
              {isTagMode ? 'Type a tag name to search across all books' : 'Type at least 2 characters to search · Use #tag for tag search'}
            </div>
          )}

          {/* Tag mode results */}
          {isTagMode && tagResults.length > 0 && (
            <div className="py-2">
              <div className="px-5 py-2 border-b border-well-800/60">
                <p className="text-[11px] text-well-500">
                  {tagResults.length} quote{tagResults.length !== 1 ? 's' : ''} tagged <span className="text-gold-400 font-semibold">#{tagQuery}</span>
                </p>
              </div>
              {Array.from(tagGroups.entries()).map(([bookId, group]) => (
                <div key={bookId}>
                  <div className="px-5 py-2 sticky top-0 bg-well-900/95 backdrop-blur-sm border-b border-well-800/60 z-10">
                    <p className="text-[11px] font-bold uppercase tracking-wider text-well-300">
                      {group.title}
                    </p>
                  </div>
                  {group.quotes.map(quote => (
                    <button
                      key={quote.id}
                      onClick={() => { router.push(`/books/${quote.book_id}?tab=quotes`); onClose() }}
                      className="w-full text-left px-5 py-3 hover:bg-well-800/60 transition-colors border-b border-well-800/20 last:border-0"
                    >
                      <p className="text-sm text-well-100 leading-relaxed">
                        &ldquo;{quote.quote_text}&rdquo;
                      </p>
                      {quote.page_number != null && (
                        <p className="text-xs text-well-400 mt-1">p.{quote.page_number}</p>
                      )}
                      {quote.tags.length > 0 && (
                        <div className="flex flex-wrap gap-1 mt-1.5">
                          {quote.tags.map(tag => (
