import type { BookNote, Quote, Book } from '@/types'

// ── PDF Export ────────────────────────────────────────────────────────────────

export async function generateNotesPDF(
  book: Book,
  notes: BookNote[],
  quotes: Quote[]
): Promise<Uint8Array> {
  const { jsPDF } = await import('jspdf')
  const doc = new jsPDF({ orientation: 'portrait', unit: 'pt', format: 'letter' })

  const margin = 40
  const pageWidth = doc.internal.pageSize.getWidth()
  const pageHeight = doc.internal.pageSize.getHeight()
  const contentWidth = pageWidth - margin * 2
  let y = margin

  function addDivider() {
    y += 10
    doc.setDrawColor(200)
    doc.line(margin, y, pageWidth - margin, y)
    y += 10
  }

  function addHeading(text: string, size = 16) {
    if (y > pageHeight - 80) { doc.addPage(); y = margin }
    doc.setFontSize(size)
    doc.setFont('helvetica', 'bold')
    doc.text(text, margin, y)
    y += size + 6
  }

  function addBody(text: string, size = 11) {
    doc.setFontSize(size)
    doc.setFont('helvetica', 'normal')
    const lines = doc.splitTextToSize(text || '(empty)', contentWidth) as string[]
    for (const line of lines) {
      if (y > pageHeight - 40) { doc.addPage(); y = margin }
      doc.text(line, margin, y)
      y += size + 4
    }
  }

  // Title
  addHeading(book.title, 20)
  addBody(`Pages: ${book.current_page} / ${book.total_pages}`, 10)
  y += 10

  // Outline
  addDivider()
  addHeading('Outline')
  const outline = notes.find(n => n.tab === 'outline')
  addBody(outline?.content ?? '')

  // Scratch
  addDivider()
  addHeading('Scratch')
  const scratch = notes.find(n => n.tab === 'scratch')
  addBody(scratch?.content ?? '')

  // Quotes
  addDivider()
  addHeading('Quotes')
  if (quotes.length === 0) {
    addBody('(no quotes)')
  } else {
    for (const quote of quotes) {
      if (y > pageHeight - 80) { doc.addPage(); y = margin }
      addBody(`"${quote.quote_text}"${quote.page_number != null ? ` — p. ${quote.page_number}` : ''}`)
      y += 4
    }
  }

  return doc.output('arraybuffer') as unknown as Uint8Array
}

'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import Link from 'next/link'
import { useParams, useSearchParams } from 'next/navigation'
import { supabase } from '@/lib/supabase'
import OutlineEditor from '@/components/OutlineEditor'
import Quotes from '@/components/Quotes'
import type { Book, Quote } from '@/types'

type Tab = 'outline' | 'scratch' | 'quotes'
type SaveStatus = 'idle' | 'saving' | 'saved'

export default function NotesPage() {
  const { id } = useParams<{ id: string }>()
  const searchParams = useSearchParams()

  const [book, setBook] = useState<Book | null>(null)
  const [notes, setNotes] = useState<Record<'outline' | 'scratch', string>>({
    outline: '',
    scratch: '',
  })
  const [quotes, setQuotes] = useState<Quote[]>([])
  const [activeTab, setActiveTab] = useState<Tab>(() => {
    const tab = searchParams.get('tab')
    if (tab === 'quotes' || tab === 'scratch' || tab === 'outline') return tab
    return 'outline'
  })
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('idle')
  const [loading, setLoading] = useState(true)
  const [notFound, setNotFound] = useState(false)

  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null)

  const load = useCallback(async () => {
    const [bookRes, notesRes, quotesRes] = await Promise.all([
      supabase.from('books').select('*').eq('id', id).single(),
      supabase.from('book_notes').select('*').eq('book_id', id),
      supabase.from('quotes').select('*').eq('book_id', id)
        .order('page_number', { ascending: true, nullsFirst: false })
        .order('created_at', { ascending: true }),
    ])

    if (bookRes.error || !bookRes.data) {
      setNotFound(true)
      setLoading(false)
      return
    }

    setBook(bookRes.data as Book)

    const notesMap: Record<string, string> = {}
    for (const note of notesRes.data ?? []) {
      notesMap[note.tab] = note.content
    }
    setNotes({
      outline: notesMap.outline ?? '',
      scratch: notesMap.scratch ?? '',
    })
    setQuotes((quotesRes.data ?? []).map(q => ({ ...q, tags: q.tags ?? [] })) as Quote[])
    setLoading(false)
  }, [id])

  useEffect(() => { load() }, [load])

  function handleNoteChange(tab: 'outline' | 'scratch', content: string) {
    setNotes(n => ({ ...n, [tab]: content }))
    setSaveStatus('saving')
    if (saveTimer.current) clearTimeout(saveTimer.current)
    saveTimer.current = setTimeout(async () => {
      await supabase
        .from('book_notes')
        .upsert({ book_id: id, tab, content }, { onConflict: 'book_id,tab' })
      setSaveStatus('saved')
      setTimeout(() => setSaveStatus('idle'), 2500)
    }, 600)
  }

  async function handleExportPDF() {
    const res = await fetch(`/api/export/pdf/${id}`)
    if (!res.ok) return
    const blob = await res.blob()
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `${book?.title ?? 'notes'}.pdf`
    a.click()
    URL.revokeObjectURL(url)
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-well-950 flex items-center justify-center text-well-400 text-sm">
        Loading…
      </div>
    )
  }

  if (notFound) {
    return (
      <div className="min-h-screen bg-well-950 flex flex-col items-center justify-center text-well-400 gap-3">
        <p className="text-lg">Book not found.</p>
        <Link href="/" className="text-sm text-cream-200 hover:text-cream-100 hover:underline transition-colors">
          ← Back to MindWell
        </Link>
      </div>
    )
  }

  const isArticle = book?.type === 'article'

  const TABS: { key: Tab; label: string }[] = [
    { key: 'outline', label: 'Outline' },
    { key: 'scratch', label: 'Scratch' },
    { key: 'quotes', label: `Quotes${quotes.length > 0 ? ` (${quotes.length})` : ''}` },
  ]

  return (
    <div className="min-h-screen bg-well-950 flex flex-col">
      {/* Header */}
      <header className="sticky top-0 z-10">

        {/* Dark top strip */}
        <div className="bg-well-950 border-b border-well-800/60 backdrop-blur-sm">
          <div className="max-w-3xl mx-auto px-6 py-4">
            <div className="flex items-center justify-between gap-4">
              <div className="flex items-center gap-3 min-w-0">
                <Link
                  href="/"
                  className="text-sm text-well-400 hover:text-well-100 shrink-0 transition-colors font-medium"
                >
                  ← MindWell
                </Link>
                <span className="text-well-700 shrink-0">|</span>
                <div className="flex items-center gap-2 min-w-0">
                  <h1 className="text-base font-semibold text-well-50 truncate">{book?.title}</h1>
                  {isArticle && (
                    <span className="text-xs text-amber-300 bg-amber-900/40 border border-amber-700/50 px-1.5 py-0.5 rounded font-medium shrink-0">
                      Article
                    </span>
                  )}
                </div>
              </div>
              <div className="flex items-center gap-3 shrink-0">
                <span className={`text-xs transition-opacity ${saveStatus === 'idle' ? 'opacity-0' : 'opacity-100'} ${saveStatus === 'saved' ? 'text-gold-400' : 'text-well-400'}`}>
                  {saveStatus === 'saving' ? 'Saving…' : 'Saved'}
                </span>
                <button
                  onClick={handleExportPDF}
                  className="text-sm text-well-400 hover:text-well-100 bg-well-800 hover:bg-well-700 px-3 py-1.5 rounded-full transition-all"
                >
                  ↓ PDF
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Tab bar */}
        <div className="bg-well-950 border-b border-well-800">
          <div className="max-w-3xl mx-auto px-6">
            <div className="flex">
              {TABS.map(tab => (
                <button
                  key={tab.key}
                  onClick={() => setActiveTab(tab.key)}
                  className={`px-4 py-3 text-sm font-medium transition-all border-b-2 ${
                    activeTab === tab.key
                      ? 'border-well-50 text-well-50 font-semibold'
                      : 'border-transparent text-well-500 hover:text-well-200 hover:border-well-700'
                  }`}
                >
                  {tab.label}
                </button>
              ))}
            </div>
          </div>
        </div>
      </header>

      {/* Content */}
      <main className="flex-1 max-w-3xl w-full mx-auto px-6 py-6">

        {/* Outline */}
        {activeTab === 'outline' && (
          <OutlineEditor
            value={notes.outline}
            onChange={content => handleNoteChange('outline', content)}
          />
        )}

        {/* Scratch */}
        {activeTab === 'scratch' && (
          <textarea
            key="scratch"
            value={notes.scratch}
            onChange={e => handleNoteChange('scratch', e.target.value)}
            placeholder="Free-form scratch space — anything goes…"
            className="w-full h-[calc(100vh-200px)] resize-none bg-well-800/60 rounded-xl border-0 px-5 py-4 text-sm text-well-100 leading-relaxed placeholder:text-well-500 focus:outline-none focus:ring-2 focus:ring-cream-200/20 transition-all"
          />
        )}

        {/* Quotes */}
        {activeTab === 'quotes' && (
          <Quotes
            bookId={id}
            quotes={quotes}
            onUpdate={setQuotes}
          />
        )}
      </main>
    </div>
  )
}

'use client'

import { useRef } from 'react'

interface Props {
  value: string
  onChange: (value: string) => void
}

// Outline levels: I. → A. → 1. → a. → i.
const LEVELS = [
  { prefix: /^(I{1,3}|IV|V?I{0,3}|IX|X{0,3}|XI{0,3}|XIV|XV|XVI|XVII|XVIII|XIX|XX)\.\s/, next: 'A' },
]

type LevelKey = 'I' | 'A' | '1' | 'a' | 'i'

interface Level {
  pattern: RegExp
  nextFn: (current: string) => string
}

const OUTLINE_LEVELS: Level[] = [
  {
    // Roman numeral: I. II. III. IV. …
    pattern: /^((?:X{0,3})(?:IX|IV|V?I{0,3}))\.\s*/,
    nextFn: incrementRoman,
  },
  {
    // Capital letter: A. B. … Z.
    pattern: /^([A-Z])\.\s*/,
    nextFn: (c) => String.fromCharCode(c.charCodeAt(0) + 1) + '. ',
  },
  {
    // Arabic number: 1. 2. …
    pattern: /^(\d+)\.\s*/,
    nextFn: (c) => (parseInt(c) + 1) + '. ',
  },
  {
    // Lowercase letter: a. b. …
    pattern: /^([a-z])\.\s*/,
    nextFn: (c) => String.fromCharCode(c.charCodeAt(0) + 1) + '. ',
  },
  {
    // Lowercase roman: i. ii. iii. iv. …
    pattern: /^((?:x{0,3})(?:ix|iv|v?i{0,3}))\.\s*/,
    nextFn: incrementLowerRoman,
  },
]

function romanToInt(r: string): number {
  const vals: Record<string, number> = { i: 1, v: 5, x: 10, l: 50, c: 100, d: 500, m: 1000, I: 1, V: 5, X: 10, L: 50, C: 100, D: 500, M: 1000 }
  let total = 0
  const s = r.toLowerCase()
  for (let i = 0; i < s.length; i++) {
    const cur = vals[s[i]] ?? 0
    const next = vals[s[i + 1]] ?? 0
    total += cur < next ? -cur : cur
  }
  return total
}

function intToRoman(num: number, upper = true): string {
  const vals = [1000, 900, 500, 400, 100, 90, 50, 40, 10, 9, 5, 4, 1]
  const syms = upper
    ? ['M', 'CM', 'D', 'CD', 'C', 'XC', 'L', 'XL', 'X', 'IX', 'V', 'IV', 'I']
    : ['m', 'cm', 'd', 'cd', 'c', 'xc', 'l', 'xl', 'x', 'ix', 'v', 'iv', 'i']
  let result = ''
  for (let i = 0; i < vals.length; i++) {
    while (num >= vals[i]) { result += syms[i]; num -= vals[i] }
  }
  return result
}

function incrementRoman(current: string): string {
  return intToRoman(romanToInt(current) + 1, true) + '. '
}

function incrementLowerRoman(current: string): string {
  return intToRoman(romanToInt(current) + 1, false) + '. '
}

function getIndent(line: string): number {
  let count = 0
  for (const ch of line) {
    if (ch === '\t') count++
    else break
  }
  return count
}

function getNextPrefix(lines: string[], currentLineIndex: number, indent: number): string {
  const indentStr = '\t'.repeat(indent)
  const levelIdx = indent % OUTLINE_LEVELS.length

  for (let i = currentLineIndex - 1; i >= 0; i--) {
    const stripped = lines[i].slice(indent)
    if (getIndent(lines[i]) === indent && stripped.length > 0) {
      const level = OUTLINE_LEVELS[levelIdx]
      const m = stripped.match(level.pattern)
      if (m) {
        return indentStr + level.nextFn(m[1])
      }
      break
    }
  }

  const level = OUTLINE_LEVELS[levelIdx]
  const firstPrefixes = ['I. ', 'A. ', '1. ', 'a. ', 'i. ']
  return indentStr + firstPrefixes[levelIdx]
}

export default function OutlineEditor({ value, onChange }: Props) {
  const ref = useRef<HTMLTextAreaElement>(null)

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>) {
    const ta = ref.current
    if (!ta) return

    const start = ta.selectionStart
    const end = ta.selectionEnd
    const text = ta.value

    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()

      const before = text.slice(0, start)
      const after = text.slice(end)
      const lines = before.split('\n')
      const currentLine = lines[lines.length - 1]
      const indent = getIndent(currentLine)
      const strippedCurrent = currentLine.slice(indent)

      const levelIdx = indent % OUTLINE_LEVELS.length
      const level = OUTLINE_LEVELS[levelIdx]
      const m = strippedCurrent.match(level.pattern)

      let newPrefix: string
      if (m && strippedCurrent.length > m[0].length) {
        newPrefix = getNextPrefix(lines, lines.length, indent)
      } else if (m && strippedCurrent.length === m[0].length) {
        const newBefore = before.slice(0, before.length - currentLine.length)
        const newText = newBefore + '\n' + after
        onChange(newText)
        requestAnimationFrame(() => {
          if (!ta) return
          const pos = newBefore.length + 1
          ta.selectionStart = pos
          ta.selectionEnd = pos
        })
        return
      } else {
        newPrefix = '\t'.repeat(indent)
      }

      const newText = before + '\n' + newPrefix + after
      onChange(newText)
      requestAnimationFrame(() => {
        if (!ta) return
        const pos = start + 1 + newPrefix.length
        ta.selectionStart = pos
        ta.selectionEnd = pos
      })
      return
    }

    if (e.key === 'Tab') {
      e.preventDefault()
      const before = text.slice(0, start)
      const after = text.slice(end)
      const lines = before.split('\n')
      const currentLine = lines[lines.length - 1]
      const indent = getIndent(currentLine)

      if (e.shiftKey) {
        if (indent === 0) return
        const newIndent = indent - 1
        const strippedLine = currentLine.slice(indent)
        const newLines = [...lines]
        newLines[newLines.length - 1] = '\t'.repeat(newIndent) + strippedLine
        const newBefore = newLines.join('\n')
        const newText = newBefore + after
        onChange(newText)
        requestAnimationFrame(() => {
          if (!ta) return
          const pos = newBefore.length
          ta.selectionStart = pos
          ta.selectionEnd = pos
        })
      } else {
        const newIndent = indent + 1
        const strippedLine = currentLine.slice(indent)

        const allLines = text.split('\n')
        const currentLineIndexInAll = before.split('\n').length - 1

        const deeperPrefix = getNextPrefix(allLines, currentLineIndexInAll, newIndent)

        const existing = OUTLINE_LEVELS[indent % OUTLINE_LEVELS.length]
        const mExisting = strippedLine.match(existing.pattern)
        const contentAfterPrefix = mExisting ? strippedLine.slice(mExisting[0].length) : strippedLine

        const newLine = deeperPrefix + contentAfterPrefix
        const newLines = [...lines]
        newLines[newLines.length - 1] = newLine
        const newBefore = newLines.join('\n')
        const newText = newBefore + after
        onChange(newText)
        requestAnimationFrame(() => {
          if (!ta) return
          const pos = newBefore.length
          ta.selectionStart = pos
          ta.selectionEnd = pos
        })
      }
    }
  }

  return (
    <textarea
      ref={ref}
      value={value}
      onChange={e => onChange(e.target.value)}
      onKeyDown={handleKeyDown}
      placeholder="Structure your notes here — use Enter to continue the list, Tab to indent (I. → A. → 1. → a. → i.)"
      className="w-full h-[calc(100vh-200px)] resize-none bg-well-800/60 rounded-xl border-0 px-5 py-4 text-sm text-well-100 leading-relaxed placeholder:text-well-500 focus:outline-none focus:ring-2 focus:ring-cream-200/20 transition-all font-mono"
    />
  )
}

import { NextRequest } from 'next/server'
import { supabase } from '@/lib/supabase'

export async function GET() {
  const { data, error } = await supabase
    .from('books')
    .select('*')
    .order('created_at', { ascending: false })
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return Response.json(data)
}

export async function POST(req: NextRequest) {
  const body = await req.json()
  const {
    title,
    type = 'book',
    current_page = 0,
    total_pages,
    sessions_per_week = 4,
  } = body

  if (!title) {
    return Response.json({ error: 'title is required' }, { status: 400 })
  }
  if (type === 'book' && !total_pages) {
    return Response.json({ error: 'total_pages is required for books' }, { status: 400 })
  }

  // Compute sort_order: next available slot among active books
  const { data: existingBooks } = await supabase
    .from('books')
    .select('sort_order')
    .eq('status', 'active')
    .eq('type', type)

  const maxOrder = Math.max(0, ...((existingBooks ?? []).map((b: { sort_order: number | null }) => b.sort_order ?? 0)))
  const sort_order = maxOrder + 1

  const { data: book, error: bookError } = await supabase
    .from('books')
    .insert({
      title,
      type,
      current_page,
      total_pages: total_pages ?? 0,
      sessions_per_week,
      status: 'active',
      sort_order,
    })
    .select()
    .single()
  if (bookError) return Response.json({ error: bookError.message }, { status: 500 })

  return Response.json({ book }, { status: 201 })
}

import { NextRequest } from 'next/server'
import { supabase } from '@/lib/supabase'

export async function GET(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const { data, error } = await supabase.from('books').select('*').eq('id', id).single()
  if (error) return Response.json({ error: error.message }, { status: 404 })
  return Response.json(data)
}

export async function PATCH(
  req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const body = await req.json()

  const { data: updatedBook, error } = await supabase
    .from('books')
    .update(body)
    .eq('id', id)
    .select()
    .single()
  if (error) return Response.json({ error: error.message }, { status: 500 })

  return Response.json(updatedBook)
}

export async function DELETE(
  _req: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const { id } = await params
  const { error } = await supabase.from('books').delete().eq('id', id)
  if (error) return Response.json({ error: error.message }, { status: 500 })
  return new Response(null, { status: 204 })
}

