'use client'

import { useState, useRef, useEffect } from 'react'
import { supabase } from '@/lib/supabase'
import type { Quote } from '@/types'

// ── Tag color assignment (light theme) ─────────────────────────────────────

const TAG_PALETTES = [
  'bg-blue-100 text-blue-700 border-blue-200',
  'bg-violet-100 text-violet-700 border-violet-200',
  'bg-emerald-100 text-emerald-700 border-emerald-200',
  'bg-amber-100 text-amber-800 border-amber-200',
  'bg-rose-100 text-rose-700 border-rose-200',
  'bg-teal-100 text-teal-700 border-teal-200',
  'bg-indigo-100 text-indigo-700 border-indigo-200',
  'bg-orange-100 text-orange-700 border-orange-200',
]

export function tagColor(tag: string): string {
  let hash = 0
  for (let i = 0; i < tag.length; i++) {
    hash = (hash * 31 + tag.charCodeAt(i)) & 0xffffffff
  }
  return TAG_PALETTES[Math.abs(hash) % TAG_PALETTES.length]
}

// ── Copy button ─────────────────────────────────────────────────────────────

function CopyButton({ text }: { text: string }) {
  const [copied, setCopied] = useState(false)

  async function handleCopy() {
    await navigator.clipboard.writeText(text)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  return (
    <button
      onClick={handleCopy}
      title="Copy quote"
      className="flex items-center gap-1 text-xs text-fog-500 hover:text-navy-600 bg-fog-100 hover:bg-fog-200 px-2 py-1 rounded-full transition-all"
    >
      {copied ? (
        <>
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3 h-3 text-emerald-600">
            <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
          </svg>
          <span className="text-emerald-600">Copied</span>
        </>
      ) : (
        <>
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3 h-3">
            <path d="M7 3.5A1.5 1.5 0 0 1 8.5 2h3.879a1.5 1.5 0 0 1 1.06.44l3.122 3.12A1.5 1.5 0 0 1 17 6.622V12.5a1.5 1.5 0 0 1-1.5 1.5h-1v-3.379a3 3 0 0 0-.879-2.121L10.5 5.379A3 3 0 0 0 8.379 4.5H7v-1Z" />
            <path d="M4.5 6A1.5 1.5 0 0 0 3 7.5v9A1.5 1.5 0 0 0 4.5 18h7a1.5 1.5 0 0 0 1.5-1.5v-5.879a1.5 1.5 0 0 0-.44-1.06L9.44 6.439A1.5 1.5 0 0 0 8.378 6H4.5Z" />
          </svg>
          Copy
        </>
      )}
    </button>
  )
}

// ── Tag input ───────────────────────────────────────────────────────────────

function TagInput({
  tags,
  onChange,
}: {
  tags: string[]
  onChange: (tags: string[]) => void
}) {
  const [input, setInput] = useState('')
  const inputRef = useRef<HTMLInputElement>(null)

  function addTag(raw: string) {
    const tag = raw.trim().toLowerCase().replace(/\s+/g, '-')
    if (!tag || tags.includes(tag)) {
      setInput('')
      return
    }
    onChange([...tags, tag])
    setInput('')
  }

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === 'Enter' || e.key === ',') {
      e.preventDefault()
      addTag(input)
    }
    if (e.key === 'Backspace' && !input && tags.length > 0) {
      onChange(tags.slice(0, -1))
    }
  }

  return (
    <div
      className="flex flex-wrap gap-1.5 items-center min-h-8 px-2 py-1.5 bg-fog-100 border border-fog-300 rounded-lg cursor-text"
      onClick={() => inputRef.current?.focus()}
    >
      {tags.map(tag => (
        <span
          key={tag}
          className={`inline-flex items-center gap-1 text-xs px-2 py-0.5 rounded-full border ${tagColor(tag)}`}
        >
          {tag}
          <button
            onClick={e => { e.stopPropagation(); onChange(tags.filter(t => t !== tag)) }}
            className="hover:opacity-70 ml-0.5 leading-none"
          >
            ×
          </button>
        </span>
      ))}
      <input
        ref={inputRef}
        value={input}
        onChange={e => setInput(e.target.value)}
        onKeyDown={handleKeyDown}
        onBlur={() => { if (input.trim()) addTag(input) }}
        placeholder={tags.length === 0 ? 'Add tags…' : ''}
        className="flex-1 min-w-[80px] bg-transparent text-xs text-navy-800 placeholder:text-fog-400 outline-none"
      />
    </div>
  )
}

// ── Quote widget ────────────────────────────────────────────────────────────

function QuoteWidget({
  quote,
  onUpdate,
  onDelete,
}: {
  quote: Quote
  onUpdate: (updated: Quote) => void
  onDelete: (id: string) => void
}) {
  const [editing, setEditing] = useState(false)
  const [showFull, setShowFull] = useState(false)
  const [editText, setEditText] = useState(quote.quote_text)
  const [editPage, setEditPage] = useState(quote.page_number?.toString() ?? '')
  const [editTags, setEditTags] = useState<string[]>(quote.tags ?? [])
  const [saving, setSaving] = useState(false)

  const isLong = quote.quote_text.length > 220
  const displayText = isLong && !showFull
    ? quote.quote_text.slice(0, 220).trim() + '…'
    : quote.quote_text

  async function handleSaveEdit() {
    setSaving(true)
    const updates = {
      quote_text: editText.trim(),
      page_number: editPage ? Number(editPage) : null,
      tags: editTags,
    }
    const { data, error } = await supabase
      .from('quotes')
      .update(updates)
      .eq('id', quote.id)
      .select()
      .single()
    if (!error && data) {
      onUpdate({ ...data as Quote, tags: (data as Quote).tags ?? [] })
    }
    setSaving(false)
    setEditing(false)
  }

  if (editing) {
    return (
      <div className="bg-white rounded-xl border-2 border-navy-300 shadow-sm p-4 space-y-3">
        <textarea
          autoFocus
          value={editText}
          onChange={e => setEditText(e.target.value)}
          rows={4}
          className="w-full resize-none bg-fog-50 border border-fog-300 rounded-lg px-3 py-2.5 text-sm text-navy-900 leading-relaxed placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all"
        />
        <div className="flex gap-2 items-center">
          <label className="text-sm text-fog-600 shrink-0">p.</label>
          <input
            type="number"
            min={1}
            value={editPage}
            onChange={e => setEditPage(e.target.value)}
            placeholder="—"
            className="w-16 bg-fog-100 border border-fog-300 rounded-lg px-2 py-2 text-sm text-navy-800 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all"
          />
        </div>
        <TagInput tags={editTags} onChange={setEditTags} />
        <div className="flex gap-2 justify-end">
          <button
            onClick={() => {
              setEditing(false)
              setEditText(quote.quote_text)
              setEditPage(quote.page_number?.toString() ?? '')
              setEditTags(quote.tags ?? [])
