      <p className="text-sm text-navy-900 italic leading-relaxed mb-3">
        &ldquo;{displayText}&rdquo;
        {isLong && (
          <button
            onClick={() => setShowFull(f => !f)}
            className="ml-1.5 text-xs text-navy-400 hover:text-navy-600 not-italic transition-colors"
          >
            {showFull ? '— less' : '… more'}
          </button>
        )}
      </p>

      {/* Metadata row: page + tags + actions */}
      <div className="flex items-center gap-2 flex-wrap">
        {quote.page_number != null && (
          <span className="text-xs text-fog-500 font-mono bg-fog-100 px-1.5 py-0.5 rounded border border-fog-300">
