'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import { useRouter } from 'next/navigation'
import type { Book, Quote, SearchResult } from '@/types'

const TAG_PALETTES = [
  'bg-blue-100 text-blue-700 border-blue-200',
  'bg-violet-100 text-violet-700 border-violet-200',
  'bg-emerald-100 text-emerald-700 border-emerald-200',
  'bg-amber-100 text-amber-800 border-amber-200',
  'bg-rose-100 text-rose-700 border-rose-200',
  'bg-teal-100 text-teal-700 border-teal-200',
  'bg-indigo-100 text-indigo-700 border-indigo-200',
  'bg-orange-100 text-orange-700 border-orange-200',
]

function tagColor(tag: string): string {
  let hash = 0
  for (let i = 0; i < tag.length; i++) {
    hash = (hash * 31 + tag.charCodeAt(i)) & 0xffffffff
  }
  return TAG_PALETTES[Math.abs(hash) % TAG_PALETTES.length]
}

function highlight(text: string, query: string): React.ReactNode {
  if (!query.trim()) return text
  const idx = text.toLowerCase().indexOf(query.toLowerCase())
  if (idx === -1) return text
  return (
    <>
      {text.slice(0, idx)}
      <mark className="bg-amber-100 text-amber-800 rounded-sm">{text.slice(idx, idx + query.length)}</mark>
      {text.slice(idx + query.length)}
    </>
  )
}

function excerpt(text: string, query: string, maxLen = 160): string {
  const idx = text.toLowerCase().indexOf(query.toLowerCase())
  if (idx === -1) return text.slice(0, maxLen) + (text.length > maxLen ? '…' : '')
  const start = Math.max(0, idx - 40)
  const end = Math.min(text.length, idx + query.length + 100)
  return (start > 0 ? '…' : '') + text.slice(start, end) + (end < text.length ? '…' : '')
}

function groupByBook(results: SearchResult[]): Map<string, { title: string; items: SearchResult[] }> {
  const map = new Map<string, { title: string; items: SearchResult[] }>()
  for (const r of results) {
    if (!map.has(r.bookId)) {
      map.set(r.bookId, { title: r.bookTitle, items: [] })
    }
    map.get(r.bookId)!.items.push(r)
  }
  return map
}

function groupTagResultsByBook(quotes: (Quote & { book: Book })[]): Map<string, { title: string; quotes: (Quote & { book: Book })[] }> {
  const map = new Map<string, { title: string; quotes: (Quote & { book: Book })[] }>()
  for (const q of quotes) {
    if (!map.has(q.book_id)) {
      map.set(q.book_id, { title: q.book.title, quotes: [] })
    }
    map.get(q.book_id)!.quotes.push(q)
  }
  return map
}

function typeLabel(r: SearchResult): string {
  if (r.type === 'quote') return 'Quote'
  const tab = r.tab ?? 'note'
  if (tab === 'scratch') return 'Brainstorm'
  return tab.charAt(0).toUpperCase() + tab.slice(1)
}

function typeBadge(r: SearchResult): string {
  if (r.type === 'quote') return 'bg-ember-100 text-ember-700 border-ember-200'
  return 'bg-fog-100 text-fog-600 border-fog-300'
}

interface Props {
  onClose: () => void
}

export default function GlobalSearch({ onClose }: Props) {
  const router = useRouter()
  const [query, setQuery] = useState('')
  const [results, setResults] = useState<SearchResult[]>([])
  const [tagResults, setTagResults] = useState<(Quote & { book: Book })[]>([])
  const [loading, setLoading] = useState(false)
  const [exportingPDF, setExportingPDF] = useState(false)
  const inputRef = useRef<HTMLInputElement>(null)
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  const isTagMode = query.trim().startsWith('#')
  const tagQuery = isTagMode ? query.trim().slice(1).trim() : ''

  useEffect(() => {
    inputRef.current?.focus()
  }, [])

  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') onClose()
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [onClose])

  const searchText = useCallback(async (q: string) => {
    if (!q.trim() || q.trim().length < 2) {
      setResults([])
      setLoading(false)
      return
    }
    setLoading(true)
    const res = await fetch(`/api/search?q=${encodeURIComponent(q.trim())}`)
    const json = await res.json()
    setResults(json.results ?? [])
    setLoading(false)
  }, [])

  const searchTag = useCallback(async (tag: string) => {
    if (!tag.trim() || tag.trim().length < 1) {
      setTagResults([])
      setLoading(false)
      return
    }
    setLoading(true)
    const res = await fetch(`/api/tag-search?tag=${encodeURIComponent(tag.trim())}`)
    const json = await res.json()
    setTagResults(json.quotes ?? [])
    setLoading(false)
  }, [])

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    const val = e.target.value
    setQuery(val)
    setResults([])
    setTagResults([])
    if (debounceRef.current) clearTimeout(debounceRef.current)

    const trimmed = val.trim()
    if (trimmed.startsWith('#')) {
      const tag = trimmed.slice(1).trim()
      debounceRef.current = setTimeout(() => searchTag(tag), 300)
    } else {
      debounceRef.current = setTimeout(() => searchText(val), 300)
    }
  }

  function navigateTo(result: SearchResult) {
    const tab = result.type === 'quote' ? 'quotes' : (result.tab === 'scratch' ? 'brainstorm' : (result.tab ?? 'outline'))
    router.push(`/?book=${result.bookId}&tab=${tab}`)
    onClose()
  }

  async function handleExportTagPDF() {
    if (!tagQuery) return
    setExportingPDF(true)
    const res = await fetch(`/api/export/tag-search?tag=${encodeURIComponent(tagQuery)}`)
    if (res.ok) {
      const blob = await res.blob()
      const url = URL.createObjectURL(blob)
      const a = document.createElement('a')
      a.href = url
      a.download = `${tagQuery}-quotes.pdf`
      a.click()
      URL.revokeObjectURL(url)
    }
    setExportingPDF(false)
  }

  const groups = groupByBook(results)
  const tagGroups = groupTagResultsByBook(tagResults)

  const minLen = isTagMode ? 1 : 2
  const hasQuery = isTagMode ? tagQuery.length >= minLen : query.trim().length >= minLen
  const hasResults = isTagMode ? tagResults.length > 0 : results.length > 0

  return (
    <div
      className="fixed inset-0 bg-navy-900/40 backdrop-blur-sm flex items-start justify-center z-50 pt-[15vh] px-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="w-full max-w-2xl bg-white rounded-2xl shadow-[0_24px_80px_rgba(14,30,53,0.2),0_0_0_1px_rgba(0,0,0,0.08)] overflow-hidden">

        {/* Search input */}
        <div className="flex items-center gap-3 px-5 py-4 border-b border-fog-200">
          {isTagMode ? (
            <span className="text-ember-600 font-semibold text-base shrink-0">#</span>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-5 h-5 text-fog-400 shrink-0">
              <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
            </svg>
          )}
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={handleChange}
            placeholder="Search notes, quotes… or #tag for tag search"
            className="flex-1 bg-transparent text-navy-900 placeholder:text-fog-400 text-base outline-none"
          />
          {loading && (
            <div className="w-4 h-4 border-2 border-fog-300 border-t-navy-500 rounded-full animate-spin shrink-0" />
          )}
          {isTagMode && tagResults.length > 0 && (
            <button
              onClick={handleExportTagPDF}
              disabled={exportingPDF}
              className="shrink-0 text-xs text-white bg-navy-700 hover:bg-navy-800 px-3 py-1.5 rounded-full font-medium transition-all disabled:opacity-50"
            >
              {exportingPDF ? 'Exporting…' : '↓ PDF'}
            </button>
          )}
          <button
            onClick={onClose}
            className="text-fog-400 hover:text-navy-700 text-xl leading-none shrink-0 transition-colors"
          >
            ×
          </button>
        </div>

        {/* Results */}
        <div className="max-h-[60vh] overflow-y-auto">
          {hasQuery && !loading && !hasResults && (
            <div className="px-5 py-10 text-center text-fog-500 text-sm">
              No results for &ldquo;{isTagMode ? `#${tagQuery}` : query}&rdquo;
            </div>
          )}

          {!hasQuery && (
            <div className="px-5 py-8 text-center text-fog-400 text-sm">
              {isTagMode ? 'Type a tag name to search across all books' : 'Type at least 2 characters to search · Use #tag for tag search'}
            </div>
          )}

          {/* Tag mode results */}
          {isTagMode && tagResults.length > 0 && (
            <div className="py-2">
              <div className="px-5 py-2 border-b border-fog-100">
                <p className="text-[11px] text-fog-500">
                  {tagResults.length} quote{tagResults.length !== 1 ? 's' : ''} tagged <span className="text-ember-600 font-semibold">#{tagQuery}</span>
                </p>
              </div>
              {Array.from(tagGroups.entries()).map(([bookId, group]) => (
                <div key={bookId}>
                  <div className="px-5 py-2 sticky top-0 bg-white/95 backdrop-blur-sm border-b border-fog-100 z-10">
                    <p className="text-[11px] font-bold uppercase tracking-wider text-fog-600">
                      {group.title}
                    </p>
                  </div>
                  {group.quotes.map(quote => (
                    <button
                      key={quote.id}
                      onClick={() => { router.push(`/?book=${quote.book_id}&tab=quotes`); onClose() }}
                      className="w-full text-left px-5 py-3 hover:bg-fog-50 transition-colors border-b border-fog-100 last:border-0"
                    >
                      <p className="text-sm text-navy-800 leading-relaxed italic">
                        &ldquo;{quote.quote_text}&rdquo;
                      </p>
                      {quote.page_number != null && (
                        <p className="text-xs text-fog-400 mt-1">p.{quote.page_number}</p>
                      )}
                      {quote.tags.length > 0 && (
                        <div className="flex flex-wrap gap-1 mt-1.5">
                          {quote.tags.map(tag => (
                            <span key={tag} className={`text-xs px-1.5 py-0.5 rounded-full border ${tagColor(tag)}`}>
                              {tag}
                            </span>
                          ))}
                        </div>
                      )}
                    </button>
                  ))}
                </div>
              ))}
            </div>
          )}

          {/* Text search results */}
          {!isTagMode && results.length > 0 && (
            <div className="py-2">
              {Array.from(groups.entries()).map(([bookId, group]) => (
                <div key={bookId}>
                  <div className="px-5 py-2 sticky top-0 bg-white/95 backdrop-blur-sm border-b border-fog-100 z-10">
                    <p className="text-[11px] font-bold uppercase tracking-wider text-fog-600">
                      {group.title}
                    </p>
                  </div>

                  {group.items.map(result => (
                    <button
                      key={`${result.type}-${result.id}`}
                      onClick={() => navigateTo(result)}
                      className="w-full text-left px-5 py-3 hover:bg-fog-50 transition-colors border-b border-fog-100 last:border-0"
                    >
                      <div className="flex items-start gap-3">
                        <span className={`shrink-0 mt-0.5 text-[10px] font-bold uppercase tracking-wider border px-1.5 py-0.5 rounded ${typeBadge(result)}`}>
                          {typeLabel(result)}
                        </span>
                        <div className="flex-1 min-w-0">
                          <p className="text-sm text-navy-800 leading-relaxed">
                            {result.type === 'quote'
                              ? <>&ldquo;{highlight(excerpt(result.content, query), query)}&rdquo;</>
                              : highlight(excerpt(result.content, query), query)
                            }
                          </p>
                          {result.type === 'quote' && result.pageNumber != null && (
                            <p className="text-xs text-fog-400 mt-1">p.{result.pageNumber}</p>
                          )}
                          {result.tags && result.tags.length > 0 && (
                            <div className="flex flex-wrap gap-1 mt-1.5">
                              {result.tags.map(tag => (
                                <span key={tag} className={`text-xs px-1.5 py-0.5 rounded-full border ${tagColor(tag)}`}>
                                  {tag}
                                </span>
                              ))}
                            </div>
                          )}
                        </div>
                      </div>
                    </button>
                  ))}
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-5 py-2.5 border-t border-fog-100 flex items-center gap-4 text-xs text-fog-400">
          <span><kbd className="font-mono bg-fog-100 px-1.5 py-0.5 rounded text-fog-500 border border-fog-200">↵</kbd> to open</span>
          <span><kbd className="font-mono bg-fog-100 px-1.5 py-0.5 rounded text-fog-500 border border-fog-200">Esc</kbd> to close</span>
          {!isTagMode && <span className="text-fog-300">Tip: type <span className="text-ember-500">#tag</span> to search by tag</span>}
        </div>
      </div>
    </div>
  )
}

