'use client'

import { useState, useEffect, useCallback } from 'react'
import Link from 'next/link'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import {
  DndContext,
  closestCenter,
  DragEndEvent,
  DragOverlay,
  DragStartEvent,
  PointerSensor,
  useDroppable,
  useSensor,
  useSensors,
} from '@dnd-kit/core'
import {
  SortableContext,
  useSortable,
  verticalListSortingStrategy,
  arrayMove,
} from '@dnd-kit/sortable'
import { CSS } from '@dnd-kit/utilities'
import AddBookModal from '@/components/AddBookModal'
import AddArticleModal from '@/components/AddArticleModal'
import EditBookModal from '@/components/EditBookModal'
import GlobalSearch from '@/components/GlobalSearch'
import type { Book } from '@/types'

const READING_SECTION = '__reading-now__'
const QUEUE_SECTION = '__next-up__'

// ── Drag handle SVG ────────────────────────────────────────────────────────────

function DragHandle() {
  return (
    <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
      <circle cx="4" cy="3" r="1.5" />
      <circle cx="8" cy="3" r="1.5" />
      <circle cx="4" cy="8" r="1.5" />
      <circle cx="8" cy="8" r="1.5" />
      <circle cx="4" cy="13" r="1.5" />
      <circle cx="8" cy="13" r="1.5" />
    </svg>
  )
}

// ── Book card content (shared between sortable row + drag overlay) ─────────────

function BookCardContent({ book }: { book: Book }) {
  const pct = book.total_pages > 0
    ? Math.round((book.current_page / book.total_pages) * 100)
    : 0
  const isQueued = book.status === 'queued'

  return (
    <div className="flex-1 min-w-0">
      <p className="font-medium text-cream-200 truncate">{book.title}</p>
      {!isQueued && (
        <div className="flex items-center gap-2.5 mt-1.5">
          <div className="w-32 bg-well-800 rounded-full h-1">
            <div
              className="bg-gold-400 h-1 rounded-full transition-all"
              style={{ width: `${pct}%` }}
            />
          </div>
          <p className="text-xs text-well-400">
            p.&nbsp;{book.current_page}/{book.total_pages}
          </p>
        </div>
      )}
    </div>
  )
}

// ── Drag overlay card ─────────────────────────────────────────────────────────

function BookDragOverlay({ book }: { book: Book }) {
  return (
    <div className="bg-well-800 rounded-xl px-4 py-3 flex items-center gap-3 shadow-[0_16px_48px_rgba(0,0,0,0.8)] cursor-grabbing opacity-95">
      <div className="text-well-500 shrink-0">
        <DragHandle />
      </div>
      <BookCardContent book={book} />
    </div>
  )
}

// ── Sortable book row ──────────────────────────────────────────────────────────

function SortableBookRow({
  book,
  onComplete,
  onEdit,
  onMoveUp,
}: {
  book: Book
  onComplete: (book: Book) => void
  onEdit: (book: Book) => void
  onMoveUp?: () => void
}) {
  const { attributes, listeners, setNodeRef, transform, transition, isDragging } = useSortable({
    id: book.id,
  })

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.35 : 1,
  }

  return (
    <div
      ref={setNodeRef}
      style={style}
      className="bg-well-900 rounded-xl px-4 py-3 flex items-center gap-3 transition-colors hover:bg-well-800 group"
    >
      {/* Drag handle */}
      <button
        {...attributes}
        {...listeners}
        className="text-well-700 hover:text-well-500 cursor-grab active:cursor-grabbing shrink-0 touch-none transition-colors"
        aria-label="Drag to reorder or move between sections"
      >
        <DragHandle />
      </button>

      <BookCardContent book={book} />

      <div className="flex items-center gap-2 shrink-0">
        <button
          onClick={() => onEdit(book)}
          className="text-xs text-well-500 hover:text-cream-200 px-2.5 py-1 rounded-md bg-well-800 hover:bg-well-700 transition-all"
        >
          Edit
        </button>
        <Link
          href={`/books/${book.id}`}
          className="text-xs text-well-500 hover:text-cream-200 px-2.5 py-1 rounded-md bg-well-800 hover:bg-well-700 transition-all"
        >
          Notes
        </Link>
        {onMoveUp ? (
          <button
            onClick={onMoveUp}
            className="text-xs text-well-500 hover:text-cream-200 px-2.5 py-1 rounded-md bg-well-800 hover:bg-well-700 transition-all"
          >
            Move Up
          </button>
        ) : (
          <button
            onClick={() => onComplete(book)}
            className="w-6 h-6 flex items-center justify-center rounded-full text-well-600 hover:text-well-950 hover:bg-cream-200 transition-all"
            title="Mark as finished"
          >
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
              <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
            </svg>
          </button>
        )}
      </div>
    </div>
  )
}

// ── Droppable section container ────────────────────────────────────────────────

function DroppableSection({
  id,
  children,
  className = '',
}: {
  id: string
  children: React.ReactNode
  className?: string
}) {
  const { setNodeRef, isOver } = useDroppable({ id })
  return (
    <div
      ref={setNodeRef}
      className={`${className} rounded-xl transition-all ${isOver ? 'ring-1 ring-inset ring-cream-200/15' : ''}`}
    >
      {children}
    </div>
  )
}

// ── Article card ───────────────────────────────────────────────────────────────

function ArticleCard({ book, onDone, onEdit }: { book: Book; onDone: () => void; onEdit: (book: Book) => void }) {
  const [loading, setLoading] = useState(false)

  async function handleDone() {
    setLoading(true)
    await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'completed' }),
    })
    onDone()
  }

  return (
    <div className="bg-well-900 rounded-xl px-4 py-3 flex items-center gap-3 hover:bg-well-800 transition-colors">
      <div className="flex-1 min-w-0">
        <p className="font-medium text-cream-200 truncate">{book.title}</p>
        <p className="text-xs text-gold-400/80 mt-0.5 font-medium">Article</p>
      </div>
      <div className="flex items-center gap-2 shrink-0">
        <button
          onClick={() => onEdit(book)}
          className="text-xs text-well-500 hover:text-cream-200 px-2.5 py-1 rounded-md bg-well-800 hover:bg-well-700 transition-all"
        >
          Edit
        </button>
        <Link
          href={`/books/${book.id}`}
          className="text-xs text-well-500 hover:text-cream-200 px-2.5 py-1 rounded-md bg-well-800 hover:bg-well-700 transition-all"
        >
          Notes
        </Link>
        <button
          onClick={handleDone}
          disabled={loading}
          className="w-6 h-6 flex items-center justify-center rounded-full text-well-600 hover:text-well-950 hover:bg-cream-200 transition-all disabled:opacity-40"
          title="Mark done"
        >
          {loading ? (
            <span className="text-[10px]">…</span>
          ) : (
            <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
              <path fillRule="evenodd" d="M16.704 4.153a.75.75 0 0 1 .143 1.052l-8 10.5a.75.75 0 0 1-1.127.075l-4.5-4.5a.75.75 0 0 1 1.06-1.06l3.894 3.893 7.48-9.817a.75.75 0 0 1 1.05-.143Z" clipRule="evenodd" />
            </svg>
          )}
        </button>
      </div>
    </div>
  )
}

// ── Confirm complete book modal ────────────────────────────────────────────────

function ConfirmCompleteModal({
  book,
  onClose,
  onConfirm,
}: {
  book: Book
  onClose: () => void
  onConfirm: () => void
}) {
  const [loading, setLoading] = useState(false)

  async function handleConfirm() {
    setLoading(true)
    await onConfirm()
    setLoading(false)
  }

  return (
    <div
      className="fixed inset-0 bg-well-950/80 backdrop-blur-sm flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-well-900 rounded-2xl shadow-[0_24px_80px_rgba(0,0,0,0.9)] w-full max-w-sm">
        <div className="px-6 py-6">
          <h2 className="font-semibold text-cream-200 mb-2">Finish &ldquo;{book.title}&rdquo;?</h2>
          <p className="text-sm text-well-300 leading-relaxed">
            This will mark the book as completed and move it to your finished list.
          </p>
          <div className="flex gap-3 mt-5">
            <button
              onClick={onClose}
              className="flex-1 bg-well-800 hover:bg-well-700 text-well-300 hover:text-well-100 px-4 py-2 rounded-full text-sm transition-all"
            >
              Cancel
            </button>
            <button
              onClick={handleConfirm}
              disabled={loading}
              className="flex-1 bg-cream-200 hover:bg-cream-100 text-well-950 px-4 py-2 rounded-full text-sm font-semibold transition-all disabled:opacity-50"
            >
              {loading ? 'Finishing…' : 'Yes, finish it'}
            </button>
          </div>
        </div>
      </div>
    </div>
  )
}

// ── Completed book card ────────────────────────────────────────────────────────

function CompletedBookCard({ book }: { book: Book }) {
  const [expanded, setExpanded] = useState(false)

  return (
    <div className="bg-well-900 rounded-xl overflow-hidden">
      <button
        onClick={() => setExpanded(e => !e)}
        className="w-full px-4 py-3 flex items-center gap-3 text-left hover:bg-well-800 transition-colors"
      >
        <span className="text-well-500 text-xs">
          {expanded ? '▾' : '▸'}
        </span>
        <p className="flex-1 font-medium text-well-300 truncate">{book.title}</p>
        {book.date_finished && (
          <span className="text-xs text-well-500 shrink-0">
            {format(parseISO(book.date_finished), 'MMM d, yyyy')}
          </span>
        )}
        <span className="text-xs text-gold-400 font-medium shrink-0">✓ Finished</span>
      </button>

      {expanded && (
        <div className="px-4 pb-4 border-t border-well-800/60 pt-3 flex items-center justify-between gap-4">
          <div className="text-xs text-well-400 space-y-0.5">
            <p>{book.total_pages} pages</p>
            {book.date_finished && (
              <p>Finished {format(parseISO(book.date_finished), 'MMMM d, yyyy')}</p>
            )}
            <p>Added {format(parseISO(book.created_at), 'MMMM d, yyyy')}</p>
          </div>
          <Link
            href={`/books/${book.id}`}
            className="text-sm text-cream-200 hover:text-cream-100 font-medium shrink-0 transition-colors"
          >
            View Notes →
          </Link>
        </div>
      )}
    </div>
  )
}

// ── Dashboard ──────────────────────────────────────────────────────────────────

export default function Dashboard() {
  const [books, setBooks] = useState<Book[]>([])
  const [loading, setLoading] = useState(true)
  const [nextUpExpanded, setNextUpExpanded] = useState(false)
  const [activeDragBookId, setActiveDragBookId] = useState<string | null>(null)

  const [showAddBook, setShowAddBook] = useState(false)
  const [showAddArticle, setShowAddArticle] = useState(false)
  const [showSearch, setShowSearch] = useState(false)
  const [completeBookTarget, setCompleteBookTarget] = useState<Book | null>(null)
  const [editBookTarget, setEditBookTarget] = useState<Book | null>(null)

  const refresh = useCallback(async () => {
    const { data } = await supabase
      .from('books')
      .select('*')
      .order('sort_order', { ascending: true, nullsFirst: false })
      .order('created_at', { ascending: false })
    setBooks((data as Book[]) ?? [])
    setLoading(false)
  }, [])

  useEffect(() => { refresh() }, [refresh])

  // Cmd+K / Ctrl+K to open search
  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault()
        setShowSearch(s => !s)
      }
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [])

  const sensors = useSensors(useSensor(PointerSensor, { activationConstraint: { distance: 8 } }))

  const readingNow = books.filter(b => b.status === 'active' && b.type === 'book')
  const nextUp = books.filter(b => (b.status === 'queued' || b.status === 'paused') && b.type === 'book')
  const activeArticles = books.filter(b => b.status === 'active' && b.type === 'article')
  const completedBooks = books.filter(b => b.status === 'completed')

  const activeDragBook = activeDragBookId
    ? books.find(b => b.id === activeDragBookId) ?? null
    : null

  async function handleMoveUp(book: Book) {
    const currentActive = readingNow[0] ?? null
    // Optimistic update
    setBooks(prev => prev.map(b => {
      if (b.id === book.id) return { ...b, status: 'active' }
      if (currentActive && b.id === currentActive.id) return { ...b, status: 'queued' }
      return b
    }))
    // Persist — displace current active book first
    if (currentActive) {
      await fetch(`/api/books/${currentActive.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: 'queued' }),
      })
    }
    await fetch(`/api/books/${book.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'active' }),
    })
  }

  function handleDragStart(event: DragStartEvent) {
    setActiveDragBookId(event.active.id as string)
    // Auto-expand Next Up so it's always a visible drop target
    setNextUpExpanded(true)
  }

  async function handleDragEnd(event: DragEndEvent) {
    const { active, over } = event
    setActiveDragBookId(null)
    if (!over) return

    const activeId = active.id as string
    const overId = over.id as string

    if (activeId === overId) return

    const inReading = readingNow.some(b => b.id === activeId)
    const inQueue = nextUp.some(b => b.id === activeId)

    const overIsReadingSection = overId === READING_SECTION
    const overIsQueueSection = overId === QUEUE_SECTION
    const overInReading = readingNow.some(b => b.id === overId)
    const overInQueue = nextUp.some(b => b.id === overId)

    // Determine destination
    let destSection: 'reading' | 'queue' | null = null
    if (overIsReadingSection || overInReading) destSection = 'reading'
    else if (overIsQueueSection || overInQueue) destSection = 'queue'
    if (!destSection) return

    const sourceSection = inReading ? 'reading' : inQueue ? 'queue' : null
    if (!sourceSection) return

    if (sourceSection === destSection) {
      // Reorder within section
      const list = sourceSection === 'reading' ? readingNow : nextUp
      const oldIndex = list.findIndex(b => b.id === activeId)
      const newIndex = (overIsReadingSection || overIsQueueSection)
        ? list.length - 1
        : list.findIndex(b => b.id === overId)
      if (oldIndex === -1 || newIndex === -1 || oldIndex === newIndex) return

      const reordered = arrayMove(list, oldIndex, newIndex)
      setBooks(prev => {
        const others = prev.filter(b => !list.some(l => l.id === b.id))
        return [...others, ...reordered.map((b, i) => ({ ...b, sort_order: i + 1 }))]
      })
      await fetch('/api/books/reorder', {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ orderedIds: reordered.map(b => b.id) }),
      })
      await refresh()
    } else {
      // Cross-section move — swap if dragging into Reading Now
      const originalStatus = books.find(b => b.id === activeId)?.status
      const newStatus = destSection === 'reading' ? 'active' : 'queued'
      const currentActive = destSection === 'reading' ? (readingNow[0] ?? null) : null

      // Optimistic update
      setBooks(prev => prev.map(b => {
        if (b.id === activeId) return { ...b, status: newStatus }
        if (currentActive && b.id === currentActive.id) return { ...b, status: 'queued' }
        return b
      }))

      // Displace existing active book first
      if (currentActive) {
        await fetch(`/api/books/${currentActive.id}`, {
          method: 'PATCH',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ status: 'queued' }),
        })
      }
      const res = await fetch(`/api/books/${activeId}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ status: newStatus }),
      })
      if (!res.ok && originalStatus) {
        // Revert optimistic update
        setBooks(prev => prev.map(b => {
          if (b.id === activeId) return { ...b, status: originalStatus }
          if (currentActive && b.id === currentActive.id) return { ...b, status: currentActive.status }
          return b
        }))
      }
    }
  }

  async function handleCompleteBook(book: Book) {
    await fetch(`/api/books/${book.id}/complete`, { method: 'POST' })
    setCompleteBookTarget(null)
    await refresh()
  }

if (loading) {
    return (
      <div className="min-h-screen bg-well-950 flex items-center justify-center text-well-400 text-sm">
        Loading…
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-well-950">
      {/* Header */}
      <header className="bg-well-950/95 border-b border-well-800/50 sticky top-0 z-10 backdrop-blur-xl">
        <div className="max-w-4xl mx-auto px-6 py-4 flex items-center justify-between">
          <h1 className="text-lg font-semibold text-cream-200 tracking-tight">MindWell</h1>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setShowSearch(true)}
              className="text-sm text-well-400 hover:text-cream-200 px-3 py-1.5 rounded-full transition-all flex items-center gap-2 bg-well-800 hover:bg-well-700"
              title="Search (⌘K)"
            >
              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-3.5 h-3.5">
                <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
              </svg>
              <span className="hidden sm:inline">Search</span>
              <kbd className="hidden sm:inline text-[10px] font-mono bg-well-700 text-well-500 px-1.5 py-0.5 rounded">⌘K</kbd>
            </button>
            <button
              onClick={() => setShowAddArticle(true)}
              className="text-sm text-well-300 hover:text-cream-200 bg-well-800 hover:bg-well-700 px-4 py-1.5 rounded-full transition-all font-medium"
            >
              + Article
            </button>
            <button
              onClick={() => setShowAddBook(true)}
              className="text-sm text-well-950 bg-cream-200 hover:bg-cream-100 px-4 py-1.5 rounded-full transition-all font-semibold"
            >
              + Book
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-6 py-8 space-y-8">
        <DndContext
          sensors={sensors}
          collisionDetection={closestCenter}
          onDragStart={handleDragStart}
          onDragEnd={handleDragEnd}
        >

          {/* ── Reading Now ── */}
          <section>
            <h2 className="text-[11px] font-bold uppercase tracking-widest text-well-500 mb-3">
              Reading Now
            </h2>

            <DroppableSection id={READING_SECTION}>
              {readingNow.length === 0 ? (
                <div className="text-center py-12 text-well-400 bg-well-900 rounded-xl">
                  <p className="text-sm text-well-500 mb-3">Nothing here yet</p>
                  <button
                    onClick={() => setShowAddBook(true)}
                    className="text-sm text-cream-200 hover:text-cream-100 transition-colors font-medium"
                  >
                    Add your first book →
                  </button>
                </div>
              ) : (
                <SortableContext items={readingNow.map(b => b.id)} strategy={verticalListSortingStrategy}>
                  <div className="space-y-2">
                    {readingNow.map(book => (
                      <SortableBookRow
                        key={book.id}
                        book={book}
                        onComplete={() => setCompleteBookTarget(book)}
                        onEdit={() => setEditBookTarget(book)}
                      />
                    ))}
                  </div>
                </SortableContext>
              )}
            </DroppableSection>
          </section>

          {/* ── Articles ── */}
          {activeArticles.length > 0 && (
            <section>
              <h2 className="text-[11px] font-bold uppercase tracking-widest text-well-500 mb-3">
                Articles
              </h2>
              <div className="space-y-2">
                {activeArticles.map(article => (
                  <ArticleCard
                    key={article.id}
                    book={article}
                    onDone={refresh}
                    onEdit={() => setEditBookTarget(article)}
                  />
                ))}
              </div>
            </section>
          )}

          {/* ── Next Up ── */}
          <section>
            <DroppableSection id={QUEUE_SECTION}>
              <button
                onClick={() => setNextUpExpanded(e => !e)}
                className="flex items-center gap-2 mb-3 group"
              >
                <h2 className="text-[11px] font-bold uppercase tracking-widest text-well-500 group-hover:text-well-300 transition-colors">
                  Next Up
                </h2>
                <span className="text-well-600 text-xs group-hover:text-well-400 transition-colors">
                  {nextUp.length > 0 ? `(${nextUp.length}) ` : ''}{nextUpExpanded ? '▾' : '▸'}
                </span>
              </button>

              {nextUpExpanded && (
                nextUp.length === 0 ? (
                  <div className="text-center py-8 text-well-500 bg-well-900 rounded-xl text-sm">
                    Drag books here from Reading Now
                  </div>
                ) : (
                  <SortableContext items={nextUp.map(b => b.id)} strategy={verticalListSortingStrategy}>
                    <div className="space-y-2">
                      {nextUp.map(book => (
                        <SortableBookRow
                          key={book.id}
                          book={book}
                          onComplete={() => setCompleteBookTarget(book)}
                          onEdit={() => setEditBookTarget(book)}
                          onMoveUp={() => handleMoveUp(book)}
                        />
                      ))}
                    </div>
                  </SortableContext>
                )
              )}
            </DroppableSection>
          </section>

          <DragOverlay dropAnimation={null}>
            {activeDragBook && <BookDragOverlay book={activeDragBook} />}
          </DragOverlay>
        </DndContext>

        {/* ── Completed ── */}
        {completedBooks.length > 0 && (
          <section>
            <h2 className="text-[11px] font-bold uppercase tracking-widest text-well-500 mb-3">
              Completed
            </h2>
            <div className="space-y-2">
              {completedBooks
                .sort((a, b) => (b.date_finished ?? '').localeCompare(a.date_finished ?? ''))
                .map(book => (
                  <CompletedBookCard key={book.id} book={book} />
                ))}
            </div>
          </section>
        )}
      </main>

      {/* Modals */}
      {showAddBook && (
        <AddBookModal onClose={() => setShowAddBook(false)} onSuccess={refresh} />
      )}

      {showAddArticle && (
        <AddArticleModal onClose={() => setShowAddArticle(false)} onSuccess={refresh} />
      )}

      {completeBookTarget && (
        <ConfirmCompleteModal
          book={completeBookTarget}
          onClose={() => setCompleteBookTarget(null)}
          onConfirm={() => handleCompleteBook(completeBookTarget)}
        />
      )}

      {editBookTarget && (
        <EditBookModal
          book={editBookTarget}
          onClose={() => setEditBookTarget(null)}
          onSuccess={() => { setEditBookTarget(null); refresh() }}
          onDelete={() => { setEditBookTarget(null); refresh() }}
        />
      )}

      {showSearch && <GlobalSearch onClose={() => setShowSearch(false)} />}

    </div>
  )
}

