                <input type="number" min={0} value={editCurrentPage} onChange={e => setEditCurrentPage(e.target.value)} placeholder="0" className={inputClass} />
              </div>
            </div>
          )}
          {book.type === 'article' && (
            <div className="grid grid-cols-2 gap-3">
