'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import OutlineEditor from './OutlineEditor'
import Quotes from './Quotes'
import type { Book, Quote } from '@/types'

type Tab = 'outline' | 'brainstorm' | 'quotes'
type SaveStatus = 'idle' | 'saving' | 'saved'

interface Props {
  bookId: string
  initialTab?: Tab
  onClose: () => void
  onDelete: (id: string) => void
  onUpdate: () => void
}

const inputClass = 'w-full bg-fog-100 border border-fog-300 rounded-lg px-3 py-2 text-sm text-navy-900 placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all'
const labelClass = 'block text-xs font-medium text-fog-600 mb-1'

export default function DetailModal({ bookId, initialTab = 'outline', onClose, onDelete, onUpdate }: Props) {
  const [book, setBook] = useState<Book | null>(null)
  const [notes, setNotes] = useState({ outline: '', scratch: '' })
  const [quotes, setQuotes] = useState<Quote[]>([])
  const [loading, setLoading] = useState(true)
  const [activeTab, setActiveTab] = useState<Tab>(initialTab)
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('idle')
  const [editing, setEditing] = useState(false)
  const [confirmDelete, setConfirmDelete] = useState(false)
  const [savingMeta, setSavingMeta] = useState(false)
  const [metaError, setMetaError] = useState('')

  // Edit form state
  const [editTitle, setEditTitle] = useState('')
  const [editAuthor, setEditAuthor] = useState('')
  const [editTotalPages, setEditTotalPages] = useState('')
  const [editCurrentPage, setEditCurrentPage] = useState('')
  const [editPublication, setEditPublication] = useState('')
  const [editArticleDate, setEditArticleDate] = useState('')
  const [editShowTitle, setEditShowTitle] = useState('')
  const [editGuests, setEditGuests] = useState('')
  const [editAirDate, setEditAirDate] = useState('')

  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null)

  const load = useCallback(async () => {
    setLoading(true)
    const [bookRes, notesRes, quotesRes] = await Promise.all([
      supabase.from('books').select('*').eq('id', bookId).single(),
      supabase.from('book_notes').select('*').eq('book_id', bookId),
      supabase.from('quotes').select('*').eq('book_id', bookId)
        .order('page_number', { ascending: true, nullsFirst: false })
        .order('created_at', { ascending: true }),
    ])

    if (!bookRes.error && bookRes.data) {
      const b = bookRes.data as Book
      setBook(b)
      setEditTitle(b.title ?? '')
      setEditAuthor(b.author ?? '')
      setEditTotalPages(b.total_pages?.toString() ?? '')
      setEditCurrentPage(b.current_page?.toString() ?? '')
      setEditPublication(b.publication ?? '')
      setEditArticleDate(b.article_date ?? '')
      setEditShowTitle(b.show_title ?? '')
      setEditGuests(b.guests ?? '')
      setEditAirDate(b.air_date ?? '')
    }

    const notesMap: Record<string, string> = {}
    for (const note of notesRes.data ?? []) {
      notesMap[note.tab] = note.content
    }
    setNotes({ outline: notesMap.outline ?? '', scratch: notesMap.scratch ?? '' })
    setQuotes((quotesRes.data ?? []).map(q => ({ ...q, tags: q.tags ?? [] })) as Quote[])
    setLoading(false)
  }, [bookId])

  useEffect(() => { load() }, [load])

  // Update tab when initialTab changes (from URL navigation)
  useEffect(() => { setActiveTab(initialTab) }, [initialTab])

  // Close on Escape
  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') {
        if (editing) { setEditing(false); setConfirmDelete(false); setMetaError('') }
        else onClose()
      }
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [onClose, editing])

  function handleNoteChange(tab: 'outline' | 'scratch', content: string) {
    setNotes(n => ({ ...n, [tab]: content }))
    setSaveStatus('saving')
    if (saveTimer.current) clearTimeout(saveTimer.current)
    saveTimer.current = setTimeout(async () => {
      await supabase
        .from('book_notes')
        .upsert({ book_id: bookId, tab, content }, { onConflict: 'book_id,tab' })
      setSaveStatus('saved')
      setTimeout(() => setSaveStatus('idle'), 2500)
    }, 600)
  }

  async function handleSaveMetadata() {
    if (!book) return
    setSavingMeta(true)
    setMetaError('')

    const updates: Record<string, string | number | null> = {
      title: editTitle.trim() || book.title,
      author: editAuthor.trim() || null,
    }

    if (book.type === 'book') {
      updates.total_pages = editTotalPages ? Number(editTotalPages) : null
      updates.current_page = editCurrentPage ? Number(editCurrentPage) : null
    } else if (book.type === 'article') {
      updates.publication = editPublication.trim() || null
      updates.article_date = editArticleDate.trim() || null
    } else if (book.type === 'podcast') {
      updates.show_title = editShowTitle.trim() || null
      updates.guests = editGuests.trim() || null
      updates.air_date = editAirDate.trim() || null
    }

    console.log('[DetailModal] saving metadata for book', bookId, updates)

    const res = await fetch(`/api/books/${bookId}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(updates),
    })

    const json = await res.json()
    setSavingMeta(false)

    if (!res.ok) {
      console.error('[DetailModal] save failed:', json)
      setMetaError(json.error ?? 'Save failed — check server logs for details.')
      return  // keep edit form open
    }

    console.log('[DetailModal] save succeeded:', json)
    setBook(json as Book)
    onUpdate()
    setEditing(false)
    setConfirmDelete(false)
  }

  async function handleDelete() {
    await supabase.from('books').delete().eq('id', bookId)
    onDelete(bookId)
  }

  async function handleExportPDF() {
    const res = await fetch(`/api/export/pdf/${bookId}`)
    if (!res.ok) return
    const blob = await res.blob()
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `${book?.title ?? 'notes'}.pdf`
    a.click()
    URL.revokeObjectURL(url)
  }

  const TABS: { key: Tab; label: string }[] = [
    { key: 'outline', label: 'Outline' },
    { key: 'brainstorm', label: 'Brainstorm' },
    { key: 'quotes', label: `Quotes${quotes.length > 0 ? ` (${quotes.length})` : ''}` },
  ]

  // Type badge
  function typeBadge(type: string) {
    if (type === 'article') return 'bg-navy-100 text-navy-700 border-navy-200'
    if (type === 'podcast') return 'bg-ember-100 text-ember-700 border-ember-200'
    return 'bg-fog-100 text-fog-600 border-fog-300'
  }
  function typeLabel(type: string) {
    if (type === 'article') return 'Article'
    if (type === 'podcast') return 'Podcast'
    return 'Book'
  }

  function renderMetadataDisplay() {
    if (!book) return null
    const subtitle: string[] = []
    if (book.type === 'book') {
      if (book.total_pages) subtitle.push(`${book.current_page ?? 0} / ${book.total_pages} pages`)
    } else if (book.type === 'article') {
      if (book.publication) subtitle.push(book.publication)
      if (book.article_date) subtitle.push(book.article_date)
    } else if (book.type === 'podcast') {
      if (book.show_title) subtitle.push(book.show_title)
      if (book.air_date) subtitle.push(book.air_date)
    }

    return (
      <div className="flex items-start justify-between gap-4">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            <span className={`text-[10px] font-bold uppercase tracking-wider border px-1.5 py-0.5 rounded ${typeBadge(book.type)}`}>
              {typeLabel(book.type)}
            </span>
            {book.date_finished && (
              <span className="text-xs text-fog-400">
                Finished {format(parseISO(book.date_finished), 'MMM d, yyyy')}
              </span>
            )}
          </div>
          <h2 className="text-xl font-semibold text-navy-900 leading-snug">{book.title}</h2>
          {book.author && <p className="text-sm text-fog-600 mt-0.5">{book.author}</p>}
          {subtitle.length > 0 && (
            <p className="text-xs text-fog-500 mt-1">{subtitle.join(' · ')}</p>
          )}
          {book.type === 'podcast' && book.guests && (
            <p className="text-xs text-fog-500 mt-0.5">with {book.guests}</p>
          )}
        </div>
        <button
          onClick={() => setEditing(true)}
          className="shrink-0 p-2 text-fog-400 hover:text-navy-600 hover:bg-fog-100 rounded-lg transition-all"
          title="Edit details"
        >
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
            <path d="M2.695 14.763l-1.262 3.154a.5.5 0 0 0 .65.65l3.155-1.262a4 4 0 0 0 1.343-.885L17.5 5.5a2.121 2.121 0 0 0-3-3L3.58 13.42a4 4 0 0 0-.885 1.343Z" />
          </svg>
        </button>
      </div>
    )
  }

  function renderEditForm() {
    if (!book) return null
    return (
      <div className="space-y-3">
        <div className="grid grid-cols-1 gap-3">
          <div>
            <label className={labelClass}>Title</label>
            <input value={editTitle} onChange={e => setEditTitle(e.target.value)} className={inputClass} />
          </div>
          <div>
            <label className={labelClass}>
              {book.type === 'podcast' ? 'Guests / Hosts' : 'Author'}
            </label>
            <input value={editAuthor} onChange={e => setEditAuthor(e.target.value)} placeholder="—" className={inputClass} />
          </div>
          {book.type === 'book' && (
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className={labelClass}>Total Pages</label>
                <input type="number" min={1} value={editTotalPages} onChange={e => setEditTotalPages(e.target.value)} placeholder="—" className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Current Page</label>
                <input type="number" min={0} value={editCurrentPage} onChange={e => setEditCurrentPage(e.target.value)} placeholder="0" className={inputClass} />
              </div>
            </div>
          )}
          {book.type === 'article' && (
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className={labelClass}>Publication</label>
                <input value={editPublication} onChange={e => setEditPublication(e.target.value)} placeholder="—" className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Date</label>
                <input value={editArticleDate} onChange={e => setEditArticleDate(e.target.value)} placeholder="—" className={inputClass} />
              </div>
            </div>
          )}
          {book.type === 'podcast' && (
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className={labelClass}>Show Title</label>
                <input value={editShowTitle} onChange={e => setEditShowTitle(e.target.value)} placeholder="—" className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Air Date</label>
                <input value={editAirDate} onChange={e => setEditAirDate(e.target.value)} placeholder="—" className={inputClass} />
              </div>
              <div className="col-span-2">
                <label className={labelClass}>Guests</label>
                <input value={editGuests} onChange={e => setEditGuests(e.target.value)} placeholder="—" className={inputClass} />
              </div>
            </div>
          )}
        </div>

        {/* Delete + Save row */}
        <div className="flex items-center gap-2 pt-1">
          {confirmDelete ? (
            <>
              <p className="text-xs text-rose-600 flex-1">Delete forever? This cannot be undone.</p>
              <button
                onClick={() => setConfirmDelete(false)}
                className="text-xs text-fog-600 hover:text-navy-700 px-3 py-1.5 rounded-lg transition-colors"
              >
                Keep it
              </button>
              <button
                onClick={handleDelete}
                className="text-xs text-white bg-rose-500 hover:bg-rose-600 px-3 py-1.5 rounded-lg font-medium transition-all"
              >
                Yes, delete
              </button>
            </>
          ) : (
            <>
              <button
                onClick={() => setConfirmDelete(true)}
                className="text-xs text-rose-500 hover:text-rose-700 px-2 py-1.5 rounded-lg transition-colors"
              >
                Delete
              </button>
              <div className="flex-1" />
              <button
                onClick={() => { setEditing(false); setConfirmDelete(false) }}
                className="text-sm text-fog-600 hover:text-navy-700 px-3 py-2 rounded-lg transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSaveMetadata}
                disabled={savingMeta}
                className="bg-navy-700 hover:bg-navy-800 text-white px-4 py-2 rounded-full text-sm font-medium transition-all disabled:opacity-50"
              >
                {savingMeta ? 'Saving…' : 'Save'}
              </button>
            </>
          )}
        </div>
      </div>
    )
  }

  if (loading) {
    return (
      <div className="fixed inset-0 bg-navy-900/40 backdrop-blur-sm flex items-center justify-center z-50">
        <div className="bg-white rounded-2xl px-8 py-6 text-navy-500 text-sm shadow-xl">
          Loading…
        </div>
      </div>
    )
  }

  if (!book) return null

  return (
    <div
      className="fixed inset-0 bg-navy-900/40 backdrop-blur-sm flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-white rounded-2xl shadow-[0_24px_80px_rgba(14,30,53,0.2)] w-full max-w-3xl max-h-[92vh] flex flex-col overflow-hidden">

        {/* Metadata section */}
        <div className="px-6 py-5 border-b border-fog-200 shrink-0">
          {editing ? renderEditForm() : renderMetadataDisplay()}
        </div>

        {/* Tab bar + controls */}
        <div className="px-6 flex items-center justify-between border-b border-fog-200 shrink-0">
          <div className="flex -mb-px">
            {TABS.map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className={`px-4 py-3 text-sm font-medium border-b-2 transition-all ${
                  activeTab === tab.key
                    ? 'border-navy-700 text-navy-700 font-semibold'
                    : 'border-transparent text-fog-500 hover:text-navy-500 hover:border-fog-300'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-3">
            <span className={`text-xs transition-opacity ${saveStatus === 'idle' ? 'opacity-0' : 'opacity-100'} ${saveStatus === 'saved' ? 'text-ember-500' : 'text-fog-400'}`}>
              {saveStatus === 'saving' ? 'Saving…' : 'Saved'}
            </span>
            <button
              onClick={handleExportPDF}
              className="text-xs text-fog-500 hover:text-navy-700 bg-fog-100 hover:bg-fog-200 px-3 py-1.5 rounded-full transition-all"
            >
              ↓ PDF
            </button>
            <button
              onClick={onClose}
              className="text-fog-400 hover:text-navy-700 text-xl leading-none transition-colors ml-1"
            >
              ×
            </button>
          </div>
        </div>

        {/* Tab content */}
        <div className="flex-1 overflow-y-auto px-6 py-5">
          {activeTab === 'outline' && (
            <OutlineEditor
              value={notes.outline}
              onChange={content => handleNoteChange('outline', content)}
              className="w-full min-h-[400px] resize-none bg-fog-100 rounded-xl border border-fog-300 px-5 py-4 text-sm text-navy-900 leading-relaxed placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all font-mono"
            />
          )}

          {activeTab === 'brainstorm' && (
            <textarea
              key="brainstorm"
              value={notes.scratch}
              onChange={e => handleNoteChange('scratch', e.target.value)}
              placeholder="Free-form brainstorm — anything goes…"
              className="w-full min-h-[400px] resize-none bg-fog-100 rounded-xl border border-fog-300 px-5 py-4 text-sm text-navy-900 leading-relaxed placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all"
            />
          )}

          {activeTab === 'quotes' && (
            <Quotes
              bookId={bookId}
              quotes={quotes}
              onUpdate={setQuotes}
            />
          )}
        </div>
      </div>
    </div>
  )
}

'use client'

import { useState, useEffect, useRef, useCallback } from 'react'
import { format, parseISO } from 'date-fns'
import { supabase } from '@/lib/supabase'
import OutlineEditor from './OutlineEditor'
import Quotes from './Quotes'
import type { Book, Quote } from '@/types'

type Tab = 'outline' | 'brainstorm' | 'quotes'
type SaveStatus = 'idle' | 'saving' | 'saved'

interface Props {
  bookId: string
  initialTab?: Tab
  onClose: () => void
  onDelete: (id: string) => void
  onUpdate: () => void
}

const inputClass = 'w-full bg-fog-100 border border-fog-300 rounded-lg px-3 py-2 text-sm text-navy-900 placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all'
const labelClass = 'block text-xs font-medium text-fog-600 mb-1'

export default function DetailModal({ bookId, initialTab = 'outline', onClose, onDelete, onUpdate }: Props) {
  const [book, setBook] = useState<Book | null>(null)
  const [notes, setNotes] = useState({ outline: '', scratch: '' })
  const [quotes, setQuotes] = useState<Quote[]>([])
  const [loading, setLoading] = useState(true)
  const [activeTab, setActiveTab] = useState<Tab>(initialTab)
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('idle')
  const [editing, setEditing] = useState(false)
  const [confirmDelete, setConfirmDelete] = useState(false)
  const [savingMeta, setSavingMeta] = useState(false)
  const [metaError, setMetaError] = useState('')

  // Edit form state
  const [editTitle, setEditTitle] = useState('')
  const [editAuthor, setEditAuthor] = useState('')
  const [editTotalPages, setEditTotalPages] = useState('')
  const [editCurrentPage, setEditCurrentPage] = useState('')
  const [editPublication, setEditPublication] = useState('')
  const [editArticleDate, setEditArticleDate] = useState('')
  const [editShowTitle, setEditShowTitle] = useState('')
  const [editGuests, setEditGuests] = useState('')
  const [editAirDate, setEditAirDate] = useState('')

  const saveTimer = useRef<ReturnType<typeof setTimeout> | null>(null)

  const load = useCallback(async () => {
    setLoading(true)
    const [bookRes, notesRes, quotesRes] = await Promise.all([
      supabase.from('books').select('*').eq('id', bookId).single(),
      supabase.from('book_notes').select('*').eq('book_id', bookId),
      supabase.from('quotes').select('*').eq('book_id', bookId)
        .order('page_number', { ascending: true, nullsFirst: false })
        .order('created_at', { ascending: true }),
    ])

    if (!bookRes.error && bookRes.data) {
      const b = bookRes.data as Book
      setBook(b)
      setEditTitle(b.title ?? '')
      setEditAuthor(b.author ?? '')
      setEditTotalPages(b.total_pages?.toString() ?? '')
      setEditCurrentPage(b.current_page?.toString() ?? '')
      setEditPublication(b.publication ?? '')
      setEditArticleDate(b.article_date ?? '')
      setEditShowTitle(b.show_title ?? '')
      setEditGuests(b.guests ?? '')
      setEditAirDate(b.air_date ?? '')
    }

    const notesMap: Record<string, string> = {}
    for (const note of notesRes.data ?? []) {
      notesMap[note.tab] = note.content
    }
    setNotes({ outline: notesMap.outline ?? '', scratch: notesMap.scratch ?? '' })
    setQuotes((quotesRes.data ?? []).map(q => ({ ...q, tags: q.tags ?? [] })) as Quote[])
    setLoading(false)
  }, [bookId])

  useEffect(() => { load() }, [load])

  // Update tab when initialTab changes (from URL navigation)
  useEffect(() => { setActiveTab(initialTab) }, [initialTab])

  // Close on Escape
  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === 'Escape') {
        if (editing) { setEditing(false); setConfirmDelete(false); setMetaError('') }
        else onClose()
      }
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [onClose, editing])

  function handleNoteChange(tab: 'outline' | 'scratch', content: string) {
    setNotes(n => ({ ...n, [tab]: content }))
    setSaveStatus('saving')
    if (saveTimer.current) clearTimeout(saveTimer.current)
    saveTimer.current = setTimeout(async () => {
      await supabase
        .from('book_notes')
        .upsert({ book_id: bookId, tab, content }, { onConflict: 'book_id,tab' })
      setSaveStatus('saved')
      setTimeout(() => setSaveStatus('idle'), 2500)
    }, 600)
  }

  async function handleSaveMetadata() {
    if (!book) return
    setSavingMeta(true)
    setMetaError('')

    const updates: Record<string, string | number | null> = {
      title: editTitle.trim() || book.title,
      author: editAuthor.trim() || null,
    }

    if (book.type === 'book') {
      updates.total_pages = editTotalPages ? Number(editTotalPages) : null
      updates.current_page = editCurrentPage ? Number(editCurrentPage) : null
    } else if (book.type === 'article') {
      updates.publication = editPublication.trim() || null
      updates.article_date = editArticleDate.trim() || null
    } else if (book.type === 'podcast') {
      updates.show_title = editShowTitle.trim() || null
      updates.guests = editGuests.trim() || null
      updates.air_date = editAirDate.trim() || null
    }

    console.log('[DetailModal] saving metadata for book', bookId, updates)

    const res = await fetch(`/api/books/${bookId}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(updates),
    })

    const json = await res.json()
    setSavingMeta(false)

    if (!res.ok) {
      console.error('[DetailModal] save failed:', json)
      setMetaError(json.error ?? 'Save failed — check server logs for details.')
      return  // keep edit form open
    }

    console.log('[DetailModal] save succeeded:', json)
    setBook(json as Book)
    onUpdate()
    setEditing(false)
    setConfirmDelete(false)
  }

  async function handleDelete() {
    await supabase.from('books').delete().eq('id', bookId)
    onDelete(bookId)
  }

  async function handleExportPDF() {
    const res = await fetch(`/api/export/pdf/${bookId}`)
    if (!res.ok) return
    const blob = await res.blob()
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `${book?.title ?? 'notes'}.pdf`
    a.click()
    URL.revokeObjectURL(url)
  }

  const TABS: { key: Tab; label: string }[] = [
    { key: 'outline', label: 'Outline' },
    { key: 'brainstorm', label: 'Brainstorm' },
    { key: 'quotes', label: `Quotes${quotes.length > 0 ? ` (${quotes.length})` : ''}` },
  ]

  // Type badge
  function typeBadge(type: string) {
    if (type === 'article') return 'bg-navy-100 text-navy-700 border-navy-200'
    if (type === 'podcast') return 'bg-ember-100 text-ember-700 border-ember-200'
    return 'bg-fog-100 text-fog-600 border-fog-300'
  }
  function typeLabel(type: string) {
    if (type === 'article') return 'Article'
    if (type === 'podcast') return 'Podcast'
    return 'Book'
  }

  function renderMetadataDisplay() {
    if (!book) return null
    const subtitle: string[] = []
    if (book.type === 'book') {
      if (book.total_pages) subtitle.push(`${book.current_page ?? 0} / ${book.total_pages} pages`)
    } else if (book.type === 'article') {
      if (book.publication) subtitle.push(book.publication)
      if (book.article_date) subtitle.push(book.article_date)
    } else if (book.type === 'podcast') {
      if (book.show_title) subtitle.push(book.show_title)
      if (book.air_date) subtitle.push(book.air_date)
    }

    return (
      <div className="flex items-start justify-between gap-4">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            <span className={`text-[10px] font-bold uppercase tracking-wider border px-1.5 py-0.5 rounded ${typeBadge(book.type)}`}>
              {typeLabel(book.type)}
            </span>
            {book.date_finished && (
              <span className="text-xs text-fog-400">
                Finished {format(parseISO(book.date_finished), 'MMM d, yyyy')}
              </span>
            )}
          </div>
          <h2 className="text-xl font-semibold text-navy-900 leading-snug">{book.title}</h2>
          {book.author && <p className="text-sm text-fog-600 mt-0.5">{book.author}</p>}
          {subtitle.length > 0 && (
            <p className="text-xs text-fog-500 mt-1">{subtitle.join(' · ')}</p>
          )}
          {book.type === 'podcast' && book.guests && (
            <p className="text-xs text-fog-500 mt-0.5">with {book.guests}</p>
          )}
        </div>
        <button
          onClick={() => setEditing(true)}
          className="shrink-0 p-2 text-fog-400 hover:text-navy-600 hover:bg-fog-100 rounded-lg transition-all"
          title="Edit details"
        >
          <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20" fill="currentColor" className="w-4 h-4">
            <path d="M2.695 14.763l-1.262 3.154a.5.5 0 0 0 .65.65l3.155-1.262a4 4 0 0 0 1.343-.885L17.5 5.5a2.121 2.121 0 0 0-3-3L3.58 13.42a4 4 0 0 0-.885 1.343Z" />
          </svg>
        </button>
      </div>
    )
  }

  function renderEditForm() {
    if (!book) return null
    return (
      <div className="space-y-3">
        <div className="grid grid-cols-1 gap-3">
          <div>
            <label className={labelClass}>Title</label>
            <input value={editTitle} onChange={e => setEditTitle(e.target.value)} className={inputClass} />
          </div>
          <div>
            <label className={labelClass}>
              {book.type === 'podcast' ? 'Guests / Hosts' : 'Author'}
            </label>
            <input value={editAuthor} onChange={e => setEditAuthor(e.target.value)} placeholder="—" className={inputClass} />
          </div>
          {book.type === 'book' && (
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className={labelClass}>Total Pages</label>
                <input type="number" min={1} value={editTotalPages} onChange={e => setEditTotalPages(e.target.value)} placeholder="—" className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Current Page</label>
                <input type="number" min={0} value={editCurrentPage} onChange={e => setEditCurrentPage(e.target.value)} placeholder="0" className={inputClass} />
              </div>
            </div>
          )}
          {book.type === 'article' && (
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className={labelClass}>Publication</label>
                <input value={editPublication} onChange={e => setEditPublication(e.target.value)} placeholder="—" className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Date</label>
                <input value={editArticleDate} onChange={e => setEditArticleDate(e.target.value)} placeholder="—" className={inputClass} />
              </div>
            </div>
          )}
          {book.type === 'podcast' && (
            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className={labelClass}>Show Title</label>
                <input value={editShowTitle} onChange={e => setEditShowTitle(e.target.value)} placeholder="—" className={inputClass} />
              </div>
              <div>
                <label className={labelClass}>Air Date</label>
                <input value={editAirDate} onChange={e => setEditAirDate(e.target.value)} placeholder="—" className={inputClass} />
              </div>
              <div className="col-span-2">
                <label className={labelClass}>Guests</label>
                <input value={editGuests} onChange={e => setEditGuests(e.target.value)} placeholder="—" className={inputClass} />
              </div>
            </div>
          )}
        </div>

        {/* Error display */}
        {metaError && (
          <p className="text-xs text-rose-600 bg-rose-50 border border-rose-200 rounded-lg px-3 py-2">
            {metaError}
          </p>
        )}

        {/* Delete + Save row */}
        <div className="flex items-center gap-2 pt-1">
          {confirmDelete ? (
            <>
              <p className="text-xs text-rose-600 flex-1">Delete forever? This cannot be undone.</p>
              <button
                onClick={() => setConfirmDelete(false)}
                className="text-xs text-fog-600 hover:text-navy-700 px-3 py-1.5 rounded-lg transition-colors"
              >
                Keep it
              </button>
              <button
                onClick={handleDelete}
                className="text-xs text-white bg-rose-500 hover:bg-rose-600 px-3 py-1.5 rounded-lg font-medium transition-all"
              >
                Yes, delete
              </button>
            </>
          ) : (
            <>
              <button
                onClick={() => setConfirmDelete(true)}
                className="text-xs text-rose-500 hover:text-rose-700 px-2 py-1.5 rounded-lg transition-colors"
              >
                Delete
              </button>
              <div className="flex-1" />
              <button
                onClick={() => { setEditing(false); setConfirmDelete(false) }}
                className="text-sm text-fog-600 hover:text-navy-700 px-3 py-2 rounded-lg transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSaveMetadata}
                disabled={savingMeta}
                className="bg-navy-700 hover:bg-navy-800 text-white px-4 py-2 rounded-full text-sm font-medium transition-all disabled:opacity-50"
              >
                {savingMeta ? 'Saving…' : 'Save'}
              </button>
            </>
          )}
        </div>
      </div>
    )
  }

  if (loading) {
    return (
      <div className="fixed inset-0 bg-navy-900/40 backdrop-blur-sm flex items-center justify-center z-50">
        <div className="bg-white rounded-2xl px-8 py-6 text-navy-500 text-sm shadow-xl">
          Loading…
        </div>
      </div>
    )
  }

  if (!book) return null

  return (
    <div
      className="fixed inset-0 bg-navy-900/40 backdrop-blur-sm flex items-center justify-center z-50 p-4"
      onClick={e => { if (e.target === e.currentTarget) onClose() }}
    >
      <div className="bg-white rounded-2xl shadow-[0_24px_80px_rgba(14,30,53,0.2)] w-full max-w-3xl max-h-[92vh] flex flex-col overflow-hidden">

        {/* Metadata section */}
        <div className="px-6 py-5 border-b border-fog-200 shrink-0">
          {editing ? renderEditForm() : renderMetadataDisplay()}
        </div>

        {/* Tab bar + controls */}
        <div className="px-6 flex items-center justify-between border-b border-fog-200 shrink-0">
          <div className="flex -mb-px">
            {TABS.map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className={`px-4 py-3 text-sm font-medium border-b-2 transition-all ${
                  activeTab === tab.key
                    ? 'border-navy-700 text-navy-700 font-semibold'
                    : 'border-transparent text-fog-500 hover:text-navy-500 hover:border-fog-300'
                }`}
              >
                {tab.label}
              </button>
            ))}
          </div>
          <div className="flex items-center gap-3">
            <span className={`text-xs transition-opacity ${saveStatus === 'idle' ? 'opacity-0' : 'opacity-100'} ${saveStatus === 'saved' ? 'text-ember-500' : 'text-fog-400'}`}>
              {saveStatus === 'saving' ? 'Saving…' : 'Saved'}
            </span>
            <button
              onClick={handleExportPDF}
              className="text-xs text-fog-500 hover:text-navy-700 bg-fog-100 hover:bg-fog-200 px-3 py-1.5 rounded-full transition-all"
            >
              ↓ PDF
            </button>
            <button
              onClick={onClose}
              className="text-fog-400 hover:text-navy-700 text-xl leading-none transition-colors ml-1"
            >
              ×
            </button>
          </div>
        </div>

        {/* Tab content */}
        <div className="flex-1 overflow-y-auto px-6 py-5">
          {activeTab === 'outline' && (
            <OutlineEditor
              value={notes.outline}
              onChange={content => handleNoteChange('outline', content)}
              className="w-full min-h-[400px] resize-none bg-fog-100 rounded-xl border border-fog-300 px-5 py-4 text-sm text-navy-900 leading-relaxed placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all font-mono"
            />
          )}

          {activeTab === 'brainstorm' && (
            <textarea
              key="brainstorm"
              value={notes.scratch}
              onChange={e => handleNoteChange('scratch', e.target.value)}
              placeholder="Free-form brainstorm — anything goes…"
              className="w-full min-h-[400px] resize-none bg-fog-100 rounded-xl border border-fog-300 px-5 py-4 text-sm text-navy-900 leading-relaxed placeholder:text-fog-400 focus:outline-none focus:ring-2 focus:ring-navy-500/20 transition-all"
            />
          )}

          {activeTab === 'quotes' && (
            <Quotes
              bookId={bookId}
              quotes={quotes}
              onUpdate={setQuotes}
            />
          )}
        </div>
      </div>
    </div>
  )
}

