@import "tailwindcss";

@theme inline {
  --font-sans: var(--font-geist);
  --font-serif: var(--font-lora);
}

@theme {
  /* Fog — light blue-gray scale */
  --color-fog-50:  #f8fafc;
  --color-fog-100: #f1f5f9;
  --color-fog-200: #e8edf2;   /* page background */
  --color-fog-300: #dde4ed;   /* card borders, dividers */
  --color-fog-400: #c2cedb;   /* muted borders */
